INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('a3f9623817f9deddd9e00', 'Aardonyx', 'Aardonyx celestae', 'Jurassic', 'Early Jurassic', 'Herbivorous', 8.0, NULL, 'uncommon', 'Africa Aardonyx is known from two immature individuals. Adults would have been much larger, probably over 10m. Aardonyx would have been largely bipedal (walking on two legs) but also capable of walking on all four legs. This and its way of feeding are transitional features between those of basal sauropodomorphs and the more derived sauropods (large dinosaurs that walked on all fours) that came later. Taxonomic details Taxonomy: Dinosauria, Saurischia, Sauropodomorpha, Prosauropoda, Anchisauria N', '[]', '/api/images/creatures/aardonyx-celestae.webp');
