INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('0a6a3ab667567ff9580b1', 'Albertaceratops', 'Albertaceratops nesmoi', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 7.0, NULL, 'uncommon', 'This dinosaur is known from a single, well-preserved skull from Alberta and material from a bone bed in Montana, including almost the entire skeleton, found in August 2001. It has long brow horns, unlike other members of the centrosaurine subfamily. Taxonomic details Taxonomy: Dinosauria, Ornithischia Named by: Ryan 2007 Type species: nesmoi Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-bo', '[]', '/api/images/creatures/albertaceratops-nesmoi.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f8daac30f3453084aedef', 'Albertosaurus', 'Albertosaurus libratus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 9.0, 1500.0, 'uncommon', 'Albertosaurus was a close relative of Tyrannosaurus , but smaller and not as heavily built. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Tyrannosauroidea, Tyrannosauridae, Albertosaurinae Named by: Lamb (1914) Type species: <d', '[]', '/api/images/creatures/albertosaurus-libratus.webp');
