INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('001ba030720b0583fdadb', 'Allosaurus', 'Allosaurus fragilis', 'Jurassic', 'Late Jurassic', 'Carnivorous', 9.7, 2700.0, 'epic', 'Allosaurus was a large meat-eating dinosaur that lived in prehistoric North America. It had three-fingered hands and distinctive horns above its eyes. Saurophaganax , a related dinosaur, was once thought to be a larger cousin of Allosaurus . But recent research has shown that Saurophaganax was probably named by mistake, and many of the bones actually b', '[]', '/api/images/creatures/allosaurus-fragilis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('917dfc4fc81d355b67811', 'Alvarezsaurus', 'Alvarezsaurus calvoi', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 2.0, NULL, 'common', 'Alvarezsaurus may have been feathered. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Neotheropoda, Tetanurae, Avetheropoda, Coelurosauria, Tyrannoraptora, Maniraptoriformes, Maniraptora, Alvarezsauridae Named by: Bonaparte (1991) Type species: calvoi Discover more <d', '[]', '/api/images/creatures/alvarezsaurus-calvoi.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('fe299d477d078487f7def', 'Amargasaurus', 'Amargasaurus cazaui', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 12.0, 9000.0, 'uncommon', 'This dinosaur had a double row of spines along its back which may have supported a twin ''sail'' of skin. The spines on its neck vertebrae were incredibly long. Taxonomic details Taxonomy: Dinosauria, Saurischia, Sauropodomorpha, Sauropoda, Diplodocoidea, Dicraeosauridae Named by: Salgado and Bonaparte (1991) Type species: cazaui Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;bo', '[]', '/api/images/creatures/amargasaurus-cazaui.webp');
