INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('e3fb548a1915de9460173', 'Ampelosaurus', 'Ampelosaurus atacis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 15.0, NULL, 'uncommon', 'Ampelosaurus is known from fossil teeth, postcranial bones and osteoderms (''armour plating''). Taxonomic details Taxonomy: Dinosauria, Saurischia, Sauropodomorpha, Sauropoda, Macronaria, Titanosauriformes, Titanosauria, Lithostrotia Named by: Le Loeuff (1995) Type species: atacis Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height', '[]', '/api/images/creatures/ampelosaurus-atacis.webp');
