INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('b93aab5eb3f01fdd74c6f', 'Ankylosaurus', 'Ankylosaurus magniventris', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 8.0, 8000.0, 'epic', 'Ankylosaurus lived during the Late Cretaceous Period in what is now North America. This armoured dinosaur had bony plates covering its body and a heavy club at the end of its tail. Though it''s the most famous member of the ankylosaur group, it''s not the best understood. Scientists still haven''t found an entire Ankylosaurus skeleton. Some other types of ankylosaurs, such as Zuul, are known from many more bones. But we do have enough Ankylosaurus remains to see that it may have been one of the big', '[]', '/api/images/creatures/ankylosaurus-magniventris.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('c69931c5ea1dd8a311ca2', 'Anserimimus', 'Anserimimus planinychus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 3.5, NULL, 'common', 'Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Ornithomimosauria, Ornithomimidae Named by: Barsbold (1988) Type species: planinychus Discover more', '[]', '/api/images/creatures/anserimimus-planinychus.webp');
