INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('e296fc855c7c5eb18d525', 'Apatosaurus', 'Apatosaurus ajax', 'Jurassic', 'Late Jurassic', 'Herbivorous', 21.0, NULL, 'rare', 'Apatosaurus was a large sauropod dinosaur. It lived around 150 million years ago in the Late Jurassic Period, in an area that is now North America. Like all sauropods, Apatosaurus ate plants. Young Apatosaurus individuals grew up quickly. They took around 10 years to reach full adult size. Where did Apatosaurus live? Apatosaurus lived alongside Stegosaurus , Diplodocus and Allosaurus . Their fossils were found in the Morrison Formation, a sequence of rocks that covers a huge area spanning severa', '[]', '/api/images/creatures/apatosaurus-ajax.webp');
