INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('8c9070083c7e894d01bda', 'Archaeoceratops', 'Archaeoceratops oshimai', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 1.3, NULL, 'common', 'Taxonomic details Taxonomy: Dinosauria, Ornithischia, Ceratopsia, Neoceratopsia Named by: Dong and Azuma (1987) Type species: oshimai Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-height:100%;max-height:100%;object-fit:cover" sizes="100vw" srcSet="/discover/dino-directory/_next/image?url=', '[]', '/api/images/creatures/archaeoceratops-oshimai.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('fa561fb0dad8632def253', 'Archaeopteryx', 'Archaeopteryx lithographica', 'Jurassic', 'Late Jurassic', 'Carnivorous', 0.5, NULL, 'legendary', 'Archaeopteryx was a small, bird-like dinosaur. It lived during the Late Jurassic Period in what is now Europe. The discovery of the first Archaeopteryx fossil in Germany in 1861 caused a lot of confusion. No birds were known from so far back. Some people even thought it might be an angel. Since then, multiple fossils of Archaeopteryx have been discovered. Many show clear evidence of long feathers. But we don''t know whether Archaeopteryx was fully able to fly or if it could only glide.<', '[]', '/api/images/creatures/archaeopteryx-lithographica.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('3cbd8d4466fbedfe377de', 'Archaeornithomimus', 'Archaeornithomimus asiaticus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 3.5, NULL, 'common', 'Uzbekistan Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Ornithomimosauria, Ornithomimidae Named by: Russell (1972) Type species: asiaticus Di', '[]', '/api/images/creatures/archaeornithomimus-asiaticus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('ecc3c998513d4eb3d3417', 'Argentinosaurus', 'Argentinosaurus huinculensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 35.0, 70000.0, 'rare', 'The exact size of Argentinosaurus is hard to estimate due to the incompleteness of its fossilised remains. But it is one of the largest land animals ever found. It carried on growing throughout most of its lifetime. Other similarly massive dinosaurs include Patagotitan and Puertasaurus . They were all titanosaurs, a type of sauropod. Argentinosaurus probably used its long neck to sweep the ground or to reach high up in search of vegetation. The hatchlings of Argentinosaurus would have taken 15 y', '[]', '/api/images/creatures/argentinosaurus-huinculensis.webp');
