INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('542c86a0499c94891f5ae', 'Borogovia', 'Borogovia gracilicrus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 1.5, NULL, 'common', 'Only partial hindlimbs of this dinosaur have been found, so reconstructions are speculative. It was named after Lewis Carroll''s borogoves from the poem Jabberwocky, published in 1871. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Troodontidae Named by: Osmolska (1987) Type species: gracilicrus Discove', '[]', '/api/images/creatures/borogovia-gracilicrus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('2d424bb39b8dbf6c85776', 'Brachiosaurus', 'Brachiosaurus altithorax', 'Jurassic', 'Late Jurassic', 'Herbivorous', 22.0, 46900.0, 'legendary', 'Brachiosaurus was a very tall plant-eating dinosaur that lived in prehistoric North America. We don’t have a complete skeleton for Brachiosaurus . Most full-body reconstructions of Brachiosaurus are based on the related African dinosaur Giraffatitan . At one time, the dinosaur now known as Giraffatitan was believed to be a species of Brachiosaurus . These days, scientists think they were two distinct species. When was Brachiosaurus discovered? The first Brachiosaurus remains were found in Colora', '[]', '/api/images/creatures/brachiosaurus-altithorax.webp');
