INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('4415897e30739863ad4c8', 'Brachytrachelopan', 'Brachytrachelopan mesai', 'Jurassic', NULL, 'Herbivorous', 10.0, NULL, 'uncommon', 'Brachytrachelopan is known from partial neck and dorsal vertebrae (part of the backbone), ribs, a partial pelvis and limb bones. This dinosaur had, proportionately, the shortest neck of any known sauropod. Taxonomic details Taxonomy: Dinosauria, Saurischia, Sauropodomorpha, Sauropoda, Diplodocoidea, Dicraeosauridae Named by: Rauhut, Remes, Fechner, Cladera and Puerta (2005) Type species: mesai Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolu', '[]', '/api/images/creatures/brachytrachelopan-mesai.webp');
