INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('cd08a4eaabb034d94ecc3', 'Carnotaurus', 'Carnotaurus sastrei', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 8.0, NULL, 'epic', 'Carnotaurus was a meat-eating dinosaur with two horns on the top of its head and very small arms. It had an unusually short snout and its head was very narrow when viewed from the front. Scientists have found lots of skin impressions for this dinosaur, so we know that it had scales over much of its body. It''s unlikely that Carnotaurus or its relatives had feathers - no evidence of them has ever been found. We also don''t have a complete skeleton. So far, nobody has ever found the tail or lower le', '[]', '/api/images/creatures/carnotaurus-sastrei.webp');
