INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('3fb2db7e3dfe11d219f3c', 'Ceratosaurus', 'Ceratosaurus nasicornis', 'Jurassic', 'Late Jurassic', 'Carnivorous', 7.0, 980.0, 'uncommon', 'Ceratosaurus was a meat-eating dinosaur that lived in North America and Europe during the Late Jurassic Period. It had a distinctive horn on its snout and a row of small, bony armour pieces running along its back. Scientists have estimated that Ceratosaurus was about six to seven metres long. It seems to have been quite a rare animal – remains of it are much rarer than those of Allosaurus that lived alongside it. A similarly', '[]', '/api/images/creatures/ceratosaurus-nasicornis.webp');
