INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('121d0927c82138f257272', 'Chindesaurus', 'Chindesaurus bryansmalli', 'Triassic', 'Late Triassic', 'Carnivorous', 4.0, NULL, 'common', 'Chindesaurus had a long whip-like tail and long legs. No skull has been found, so its reconstruction is guesswork based on similar dinosaurs. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Herrerasauridae Named by: Long and Murry (1995) Type species: bryansmalli Discover more <div class="lay', '[]', '/api/images/creatures/chindesaurus-bryansmalli.webp');
