INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('46a7ad26444dd0fa67f4f', 'Conchoraptor', 'Conchoraptor gracilis', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 1.5, NULL, 'common', 'Remains of this dinosaur have been found with feathers preserved. Sexual differences can be seen in the plumage. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Neotheropoda, Tetanurae, Avetheropoda, Coelurosauria, Tyrannoraptora, Maniraptoriformes, Maniraptora, Oviraptorosauria, Caenagnathoidea, Oviraptoridae, Ingeniinae Named by: Barsbold (1986) Type species: gracilis <div class="px-s-m', '[]', '/api/images/creatures/conchoraptor-gracilis.webp');
