INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('1fa97d480ca101f9ef135', 'Cryolophosaurus', 'Cryolophosaurus elliotti', 'Jurassic', 'Early Jurassic', 'Carnivorous', 8.0, 500.0, 'uncommon', 'Cryolophosaurus is one of the earliest meat-eating dinosaurs found so far. It lived in what is now Antarctica and had a small curved crest on the top of its head. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Neotheropoda, Tetanurae, Avetheropoda, Carnosauria Named by:</dt', '[]', '/api/images/creatures/cryolophosaurus-elliotti.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('07ea45db3fa1c379e1661', 'Dacentrurus', 'Dacentrurus armatus', 'Jurassic', 'Late Jurassic', 'Herbivorous', 6.0, NULL, 'uncommon', 'France , Portugal , United Kingdom Dacentrurus was the first stegosaur ever discovered. Taxonomic details Taxonomy: Dinosauria, Ornithischia, Thyreophora, Stegosauria, Stegosauridae Named by: Lucas (1902) Type species: armatus Discover more <img alt="" src="data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:', '[]', '/api/images/creatures/dacentrurus-armatus.webp');
