INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('73c2101cb11150082a6ac', 'Deinonychus', 'Deinonychus antirrhopus', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 3.4, 100.0, 'epic', 'Deinonychus was a small meat-eating dinosaur. It lived in what is now North America during the Early Cretaceous Period. This dinosaur had a large, sickle-shaped talon on the second toe of each foot. When not in use the claw was held off the ground to keep it sharp. The species name - antirrhopus - means ''counterbalancing''. This is because Deinonychus '' tail was long and stiff, helping to balance the animal''s weight. <h2 class="text-step-4 font-headline font-semibol', '[]', '/api/images/creatures/deinonychus-antirrhopus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('7b3577bbf1eeaaa9561e0', 'Deltadromeus', 'Deltadromeus agilis', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 8.1, NULL, 'uncommon', 'Deltadromeus is known from a single partial skeleton. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Neotheropoda, Tetanurae, Avetheropoda, Coelurosauria Named by: Sereno, Duthiel, Iarochene, Larsson, Lyon, Magwene, Sidor, Varricchio and Wilson (1996) Type species: agilis Discover m', '[]', '/api/images/creatures/deltadromeus-agilis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('647376305d1c9f4534f3a', 'Dicraeosaurus', 'Dicraeosaurus hansemanni', 'Jurassic', 'Late Jurassic', 'Herbivorous', 20.0, NULL, 'rare', 'This dinosaur is named ''forked lizard'' because of the forked spines in its backbone. Taxonomic details Taxonomy: Dinosauria, Saurischia, Sauropodomorpha, Sauropoda, Diplodocoidea, Dicraeosauridae Named by: Janensch (1914) Type species: hansemanni Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;', '[]', '/api/images/creatures/dicraeosaurus-hansemanni.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('b8565efa4c39eb000819c', 'Dilophosaurus', 'Dilophosaurus', 'Jurassic', 'Early Jurassic', 'Carnivorous', 7.0, 400.0, 'rare', 'Dilophosaurus was a meat-eating dinosaur that lived in what''s now North America. It gets its name - meaning ''two-crested lizard'' - from the distinctive double crests on top of its head. In life, they would probably be covered with hard keratin, the same material that makes up human hair and fingernails. The crests may have looked larger or a different shape to what we can see from the fossil skull. Nobody is certain what the crests were for. The most likely theories are th', '[]', '/api/images/creatures/dilophosaurus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('2eaa4cbac5a71f5adb46c', 'Diplodocus', 'Diplodocus longus', 'Jurassic', 'Late Jurassic', 'Herbivorous', 26.0, 15000.0, 'epic', 'Diplodocus had a long neck that it would have used to reach high and low vegetation, and to drink water. There’s been some debate over how it would have held such a long neck. Scientists now think that ligaments running from the hip to the back of the neck would have allowed Diplodocus to hold its neck in a horizontal position without using muscles. The back bones are split down the middle, creating a space that could have held the ligaments. Diplodocus had a very long, whip-like tail and it may', '[]', '/api/images/creatures/diplodocus-longus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('ef14859df8ea4f922cc6f', 'Dromaeosaurus', 'Dromaeosaurus albertensis', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 1.8, 15.0, 'common', 'The back foot of this dinosaur had a large claw for kicking. Taxonomic details Taxonomy: Dinosauria, Saur', '[]', '/api/images/creatures/dromaeosaurus-albertensis.webp');
