INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('521000328436dbeaf3a78', 'Dryosaurus', 'Dryosaurus altus', 'Jurassic', 'Late Jurassic', 'Herbivorous', 4.0, NULL, 'common', 'Taxonomic details Taxonomy: Dinosauria, Ornithischia, Ornithopoda, Euornithopoda, Iguanadontia, Euiguanadontia, Dryomorpha, Dryosauridae Named by: Marsh (1894) Type species: altus Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-height:100%;max-height:100%;object-fit:cover" sizes="100vw" src', '[]', '/api/images/creatures/dryosaurus-altus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('60314c0e5b0d9fdd9389b', 'Dryptosaurus', 'Dryptosaurus aquilunguis', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 6.4, NULL, 'uncommon', 'This dinosaur was originally named Laelaps by Edward Drinker Cope. His rival Othniel Charles Marsh realised that this name was already being used for a mite and renamed the dinosaur Dryptosaurus in 1877. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Tyrannosauroidea Named by: Cope (1866) Type species: aquilunguis <h2 class="text-step-4 f', '[]', '/api/images/creatures/dryptosaurus-aquilunguis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('ee68ed342d11b6f8ab6e2', 'Dubreuillosaurus', 'Dubreuillosaurus valesdunensis', 'Jurassic', 'Late Jurassic', 'Carnivorous', NULL, NULL, 'common', 'Partial skull and partial skeletons of Dubreuillosaurus have been found, but not enough to work out its overall size, although we know it was a large dinosaur. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Megalosauridae, Eustreptospondylinae Named by: Allain (2005) Type species: valesdunensis Discover more <div class', '[]', '/api/images/creatures/dubreuillosaurus-valesdunensis.webp');
