INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('cd550a9e51b47127978c8', 'Edmontosaurus', 'Edmontosaurus regalis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 13.0, 3400.0, 'uncommon', 'Hard conifer needles, twigs and seeeds have been found in Edmontosaurus stomachs. Mummified specimens have some preserved skin, so we know its texture (but not the colour). Taxonomic details Taxonomy: Dinosauria, Ornithischia, Ornithopoda, Hadrosauridae, Euhadrosauria, Hadrosaurinae Named by: Lambe (1917) Type species: regalis Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;bor', '[]', '/api/images/creatures/edmontosaurus-regalis.webp');
