INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('eab44f2797e7a99fb16af', 'Giganotosaurus', 'Giganotosaurus carolinii', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 13.0, 13800.0, 'epic', 'Giganotosaurus was a very large meat-eating dinosaur that lived in prehistoric South America. Scientists haven’t yet discovered a complete Giganotosaurus specimen. Some of the skeleton is still unknown. Was Giganotosaurus the biggest meat-eating dinosaur? Without having the full skeleton, it’s hard to say for sure just how big Giganotosa', '[]', '/api/images/creatures/giganotosaurus-carolinii.webp');
