INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('0d4e9b9bcc57d566170dc', 'Graciliceratops', 'Graciliceratops mongoliensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', NULL, NULL, 'common', 'Graciliceratops have been found. This was a tiny dinosaur, it may have only been 80cm long. Taxonomic details Taxonomy: Dinosauria, Ornithischia, Ceratopsia, Neoceratopsia Named by: Sereno (2000) Type species: mongoliensis Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-height:100%;max-heig', '[]', '/api/images/creatures/graciliceratops-mongoliensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('6f2970322b1da138a430a', 'Gryposaurus', 'Gryposaurus notabilis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 10.0, NULL, 'uncommon', 'Gryposaurus is known from several skeletons, including one which is fully articulated (the bones were joined as they would have been when the dinosaur was alive). Taxonomic details Taxonomy: Dinosauria, Ornithischia, Ornithopoda, Hadrosauridae, Euhadrosauria, Hadrosaurinae Named by: Lambe (1914) Type species: notabilis Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none', '[]', '/api/images/creatures/gryposaurus-notabilis.webp');
