INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('5c19757a840f0c403b6ab', 'Guanlong', 'Guanlong wucaii', 'Jurassic', 'Late Jurassic', 'Carnivorous', 3.0, NULL, 'common', 'Guanlong had an air-filled crest on its head. It is the earliest known tyrannosauroid ( Tyrannosaurus -like) dinosaur. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Tyrannosauroidea Named by: Xu, Clark, Forster, Norell, Erickson, Eberth, Jia and Zhao (2006) Type species: wucaii Discover more</', '[]', '/api/images/creatures/guanlong-wucaii.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('b659b5ae71054da4bc249', 'Hadrosaurus', 'Hadrosaurus foulkii', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 9.0, NULL, 'uncommon', 'Hadrosaurus was a large, two-legged herbivore from the hadrosaur group of dinosaurs. It would have cropped vegetation with its beak. It was called Hadrosaurus , which means ''bulky lizard'', because it was so large and so heavy. It was the first hadrosaur ever named. Hadrosaurus may have been hunted by large tyrannosaurs but giant crocodiles would have also been a danger in Cretaceous North America. Taxonomic details Taxonomy: Dinosauria, Ornithischia, Ornithopoda, Hadrosauridae, Euhadrosauria, Ha', '[]', '/api/images/creatures/hadrosaurus-foulkii.webp');
