INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('03a67ff9f9d134b253ade', 'Huayangosaurus', 'Huayangosaurus taibaii', 'Jurassic', NULL, 'Herbivorous', 4.5, NULL, 'common', 'Taxonomic details Taxonomy: Dinosauria, Ornithischia, Thyreophora, Stegosauria, Huayangosauridae Named by: Dong, Tang and Zhou (1982) Type species: taibaii Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-height:100%;max-height:100%;object-fit:cover" sizes="100vw" srcSet="/discover/dino-dire', '[]', '/api/images/creatures/huayangosaurus-taibaii.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('dbf772917391d9acd165c', 'Hylaeosaurus', 'Hylaeosaurus armatus', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 5.0, NULL, 'common', 'United Kingdom A specimen of Hylaeosaurus was one of the 3 fossils first identified as dinosaurs by Richard Owen in 1841. Taxonomic details Taxonomy: Dinosauria, Ornithischia, Thyreophora, Ankylosauria Named by: Mantell (1833) Type species: armatus Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100', '[]', '/api/images/creatures/hylaeosaurus-armatus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('49cdd6275fd5f00f6275b', 'Hypacrosaurus', 'Hypacrosaurus altispinus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 9.0, NULL, 'uncommon', 'Complete Hypacrosaurus skeletons have been found, from embryos to adults. Taxonomic details Taxonomy: Dinosauria, Ornithischia, Ornithopoda, Hadrosauridae, Lambeosaurinae Named by: Brown (1913) Type species: altispinus Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-height:100%;max-height:1', '[]', '/api/images/creatures/hypacrosaurus-altispinus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('5decafa1fbf456197e1e2', 'Hypsilophodon', 'Hypsilophodon foxii', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 2.0, 20.0, 'common', 'United Kingdom Hypsilophodon was a small, agile dinosaur that lived in prehistoric England. Scientists used to think Hypsilophodon spent a lot of time in trees. This came from a misunderstanding of the dinosaur’s toe bones. We now know Hypsilophodon lived on the ground and was good at running. Several Hypsilophodon individuals were discovered together at one fossil site, suggesting they lived and died together. Some experts say this dinosaur probably lived in groups, like deer. Where did Hypsilo', '[]', '/api/images/creatures/hypsilophodon-foxii.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('ff5c151ba5f7d38c1bac0', 'Iguanodon', 'Iguanodon bernissartensis', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 10.0, 4000.0, 'rare', 'England , United Kingdom Iguanodon could probably walk on all fours or on two legs. It had a large thumb spike on the end of its hand, probably to fend-off predators, and the structure of the muscles inside its head suggest it had a very long tongue. Taxonomic details Taxonomy: Dinosauria, Ornithischia, Ornithopoda, Euornithopoda, Iguanadontia, Euiguanadontia, Dryomorpha, Ankylopollexia, Iguanodontoidea Named by: Boulenger and van Beneden (1881) Type species: bernissartensis Discover more <img a', '[]', '/api/images/creatures/iguanodon-bernissartensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('c256e8a3bad39112c8469', 'Indosuchus', 'Indosuchus raptorius', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 7.0, NULL, 'uncommon', 'An almost complete skeleton of Indosuchus has been found. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Ceratosauria, Neoceratosauria Named by: Huene and Matley (1933) Type species: raptorius Discover more <a href="h', '[]', '/api/images/creatures/indosuchus-raptorius.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('1df77d88614e1bfef9a28', 'Irritator', 'Irritator challengeri', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 6.5, NULL, 'uncommon', 'Irritator was quite like Spinosaurus . It is known only from a skull, so the sail is a guess. The type species, Irritator challengeri was named after Professor Challenger from Arthur Conan Doyle''s novel ''The Lost World'', published in 1912. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Spinosauridae, Spinosaurini Named by: Martill, Cruickshank, Frey, Small and Clarke (1996) Type species: challengeri</dd', '[]', '/api/images/creatures/irritator-challengeri.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('c653c9e86cc996627720c', 'Isisaurus', 'Isisaurus colberti', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', NULL, NULL, 'common', 'This dinosaur is the one most similar to modern-day giraffes. Fungus has been found in its poo! Taxonomic details Taxonomy: Dinosauria, Saurischia, Sauropodomorpha, Sauropoda, Macronaria, Titanosauriformes, Titanosauria, Lithostrotia Named by: Jain and Bandyopadhyay (1997) Type species: colberti Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:blo', '[]', '/api/images/creatures/isisaurus-colberti.webp');
