INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('6f1e71201ae062bf9b0f1', 'Juravenator', 'Juravenator starki', 'Jurassic', 'Late Jurassic', 'Carnivorous', 0.8, NULL, 'common', 'Juravenator was the second non-avian (not bird-like) theropod (small meat-eating dinosaur) to be found in the region of Solnhofen. The type specimen shows impressions of scaly skin along the tail. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Compsognathidae Named by: Göhlich & Chiappe (2006) Type species: starki <h2', '[]', '/api/images/creatures/juravenator-starki.webp');
