INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('9faec0f96a4a346429098', 'Mapusaurus', 'Mapusaurus roseae', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 13.0, NULL, 'uncommon', 'This dinosaur may have hunted in packs and lived in family groups. Mapusaurus may have been larger than Giganotosaurus , making it the largest meat eating dinosaur found so far. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Allosauridae, Charcharodontosauridae, Giganotosaurinae Named by: Coria and Currie (2006) Type species: roseae <div', '[]', '/api/images/creatures/mapusaurus-roseae.webp');
