INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f84d14ccfbeb891fe6d8d', 'Maxakalisaurus', 'Maxakalisaurus topai', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 13.0, NULL, 'uncommon', 'Maxakalisaurus is known from a partial skeleton, including some skull fragments and osteoderms (large skin adornments). Its teeth were ridged, unusual for sauropods. Some of the bones bear teeth marks, suggesting scavenging activity. Taxonomic details Taxonomy: Dinosauria, Saurischia, Sauropodomorpha, Sauropoda, Macronaria, Titanosauriformes, Titanosauria, Lithostrotia, Saltasauridae, Saltasaurinae Named by: Kellner et al. (2006) Type species: topai Discover more <img alt="" loading="lazy" decod', '[]', '/api/images/creatures/maxakalisaurus-topai.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('c0a35a15db939e3630720', 'Megalosaurus', 'Megalosaurus bucklandii', 'Jurassic', NULL, 'Carnivorous', 6.0, NULL, 'uncommon', 'United Kingdom Megalosaurus was a large, meat-eating dinosaur. It was one of the first dinosaurs ever found and the first named. When and where was Megalosaurus found? When Megalosaurus fossils were first discovered during the seventeenth and eighteenth centuries, nobody knew what a dinosaur was. From time to time, somebody would find something unusu', '[]', '/api/images/creatures/megalosaurus-bucklandii.webp');
