INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f7557ea01e447259cbe1a', 'Metriacanthosaurus', 'Metriacanthosaurus parkeri', 'Jurassic', 'Late Jurassic', 'Carnivorous', 8.2, NULL, 'uncommon', 'United Kingdom Metriacanthosaurus is known only from a partial postcranial skeleton, so reconstructions are guesswork based on similar dinosaurs. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Neotheropoda, Tetanurae Named by:</dt', '[]', '/api/images/creatures/metriacanthosaurus-parkeri.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('8f6eea9678604a9d38fd9', 'Microceratus', 'Microceratus gobiensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 0.5, NULL, 'common', 'Mongolia This dinosaur was originally named Microceratops but, 50 years later, scientists realised that the name had already been taken by a species of beetle. So, in 2008, the name was changed to Microceratus . We don''t know how large this dinosaur would''ve grown to be, because the only fossils we know of come from a juvenile dinosaur. But scientists think that it was rather small and agile, and able to evade predators simply by running away. Taxonomic details Taxonomy: Dinosauria, Ornithischia', '[]', '/api/images/creatures/microceratus-gobiensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('13f15c952ada8d7b795f0', 'Micropachycephalosaurus', 'Micropachycephalosaurus hongtuyanensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 0.6, NULL, 'epic', 'Taxonomic details Taxonomy: Dinosauria, Ornithischia, Neornithischia, Cerapoda, Marginocephalia, Pachycephalosauria Named by: Dong (1978) Type species: hongtuyanensis Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-height:100%;max-height:100%;object-fit:cover" sizes="100vw" srcSet="/discove', '[]', '/api/images/creatures/micropachycephalosaurus-hongtuyanensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('5170dae80cf5b17a81ac0', 'Microraptor', 'Microraptor zhaoianus', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 0.8, 1.0, 'rare', 'Microraptor was a very small, feathered dinosaur with wings on its legs as well as its arms. As a member of the dromaeosaur group, it was related to the well-known dinosaur, Velociraptor . Of all the dromaeosaurs, we have the most fossils for Microraptor . Around 300 specimens have been found so far, indicating that this was a very common dinosaur. Another winged dinosaur, originally named Cryptovolans , is now thought to be the sam', '[]', '/api/images/creatures/microraptor-zhaoianus.webp');
