INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('5299cb8e5da92f448a816', 'Neuquenosaurus', 'Neuquenosaurus australis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 15.0, NULL, 'uncommon', 'Neuquensaurus was a relatively small sauropod. It had hardened, bone-like, raised scales on its back, which would have acted as protective armour. This was quite unusual for a sauropod, but some of its closest relatives - such as Antarctosaurus and Saltosaurus - might also have had them. Taxonomic details Taxonomy: Dinosauria, Saurischia, Sauropodomorpha, Sauropoda, Macronaria, Titanosauriformes, Titanosauria, Lithostrotia, Saltasauridae Named by: Lydekker (1893) Type species: australis Discover', '[]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('1a925229e7c49a9f3c36d', 'Nigersaurus', 'Nigersaurus taqueti', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 15.0, NULL, 'uncommon', 'Niger , Tunisia A partial Nigersaurus skull and numerous postcranial bones have been found. Taxonomic details Taxonomy: Dinosauria, Saurischia, Sauropodomorpha, Sauropoda, Diplodocoidea, Rebbachisauridae Named by: Sereno, Beck, Dutheil, Larsson, Lyon, Moussa, Sadleir, Sidor, Varricchio, Wilson & Wilson (1999) Type species: taqueti Discover more <', '[]', '/api/images/creatures/nigersaurus-taqueti.webp');
