INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('58674fdc3cb42f03e0f23', 'Noasaurus', 'Noasaurus leali', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 1.0, NULL, 'common', 'Noasaurus have been found. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Ceratosauria, Neoceratosauria, Abelisauroidea, Abelisauria Named by: Bonaparte and Powell (1980) Type species: leali Discover more <div class="layout-', '[]', '/api/images/creatures/noasaurus-leali.webp');
