INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('2b4d7fc1b45e572c7af19', 'Nqwebasaurus', 'Nqwebasaurus thwazi', 'Jurassic', NULL, 'Carnivorous', 1.0, NULL, 'common', 'Africa Nqwebasaurus is known from a partial skeleton lacking the skull, so the shape of the head is based on similar dinosaurs. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Neotheropoda, Tetanurae, Avetheropoda, Coelurosauria Named by: de Klerk, Forster, Sampson, Chinsamy and Ross (2000) Type species: thwazi <h2 class="text-step-4 font-', '[]', '/api/images/creatures/nqwebasaurus-thwazi.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('0a02a8a756e0cf76123ed', 'Omeisaurus', 'Omeisaurus junghsiensis', 'Jurassic', NULL, 'Herbivorous', 20.0, NULL, 'rare', 'Taxonomic details Taxonomy: Dinosauria, Saurischia, Sauropodomorpha, Sauropoda, Eusauropoda Named by: Young (1939) Type species: junghsiensis Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-height:100%;max-height:100%;object-fit:cover" sizes="100vw" srcSet="/discover/dino-directory/_next/im', '[]', '/api/images/creatures/omeisaurus-junghsiensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('ee1551fd759d81e919b12', 'Opisthocoelicaudia', 'Opisthocoelicaudia skarzynskii', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 12.0, NULL, 'uncommon', 'Opisthocoelicaudia is known from a skeleton that lacks the skull and neck, so their reconstruction is based on similar dinosaurs. Taxonomic details Taxonomy: Dinosauria, Saurischia, Sauropodomorpha, Sauropoda, Macronaria, Titanosauriformes, Titanosauria, Lithostrotia, Saltasauridae Named by: Borsuk-Bialynicka (1977) Type species: skarzynskii Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-bo', '[]', '/api/images/creatures/opisthocoelicaudia-skarzynskii.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('4712b43e90017d52c2d90', 'Ornitholestes', 'Ornitholestes hermanni', 'Jurassic', 'Late Jurassic', 'Carnivorous', 2.0, NULL, 'common', 'Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Neotheropoda, Tetanurae, Avetheropoda, Coelurosauria Named by: Osbourne (1933) Type species: hermanni Discover more <a href="https://www.nhm.ac.uk/discover/how-dinosaurs-evolved-into-birds.html" class="group flex flex-col no-underline undefin', '[]', '/api/images/creatures/ornitholestes-hermanni.webp');
