INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('efd76793787dfe3bbffc8', 'Orodromeus', 'Orodromeus makelai', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 2.0, 50.0, 'common', 'Taxonomic details Taxonomy: Dinosauria, Ornithischia, Ornithopoda, Euornithopoda Named by: Horner and Weishampel (1988) Type species: makelai Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-height:100%;max-height:100%;object-fit:cover" sizes="100vw" srcSet="/discover/dino-directory/_next/im', '[]', '/api/images/creatures/orodromeus-makelai.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('e45eac02a9a7f0438ce22', 'Oryctodromeus', 'Oryctodromeus cubicularis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 2.1, NULL, 'common', 'Remains of this dinosaur were found in its burrow, along with the remains of 2 juveniles. The burrow was around 30cm wide and 70cm long. The holotype adult specimen (the specimen that was first used to describe the species) consists of skull bones, vertebrae, ribs, scapulocoracoid, humerus, ulna, radius, tibiae, partial fibula, and a metatarsal. Taxonomic details Taxonomy: Dinosauria, Ornithischia Named by: Varricchio, Marin and Katsura (2007) Type species: cubicularis Discover more <img alt="" ', '[]', '/api/images/creatures/oryctodromeus-cubicularis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('1c7a0781f798a9d9e1438', 'Othnielia', 'Othnielia rex', 'Jurassic', 'Late Jurassic', 'Herbivorous', 1.4, NULL, 'common', 'Scientists no longer consider this a valid dinosaur. Taxonomic details Taxonomy: Dinosauria, Ornithischia, Ornithopoda, Euornithopoda Named by: Marsh (1877) Type species: rex Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-height:100%;max-height:100%;object-fit:cover" sizes="100vw" srcSet="', '[]', '/api/images/creatures/othnielia-rex.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('0f8853cd529862aee76d6', 'Ouranosaurus', 'Ouranosaurus nigeriensis', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 7.0, NULL, 'uncommon', 'Taxonomic details Taxonomy: Dinosauria, Ornithischia, Ornithopoda, Euornithopoda, Iguanadontia, Euiguanadontia, Dryomorpha, Ankylopollexia, Iguanodontoidea Named by: Taquet (1976) Type species: nigeriensis Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-height:100%;max-height:100%;object-fi', '[]', '/api/images/creatures/ouranosaurus-nigeriensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('9ae3bce648d80de4a9dc4', 'Oviraptor', 'Oviraptor philoceratops', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 2.0, 20.0, 'rare', '', '[]', '/api/images/creatures/oviraptor-philoceratops.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('2093ebcc64f403e09b6dd', 'Pachycephalosaurus', 'Pachycephalosaurus wyomingensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 3.0, 450.0, 'epic', 'Pachycephalosaurus was an unusual-looking dinosaur. It stood on two legs, had a beak for cropping plants and had a large bony dome on its head surrounded by spikes and bumps. Some scientists think that the animal used its hard dome in head-butting contests, similar to the way modern-day rams use their horns. Other experts think that the head dome may have been used for display. Perhaps it had many uses - like the antlers of modern deer, which are used both for fighting and for display. When and ', '[]', '/api/images/creatures/pachycephalosaurus-wyomingensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('8f17f37c09011b66fe8cb', 'Pachyrhinosaurus', 'Pachyrhinosaurus canadensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 8.0, 4000.0, 'uncommon', 'Pachyrhinosaurus was a plant-eating dinosaur that lived in prehistoric Alberta, Canada, and Alaska, USA. It was a member of the ceratopsian dinosaur group , which also includes the well-known horned dinosaur Triceratops . But unlike Triceratops , Pachyrhinosaurus didn’t have a nose horn. Instead, it had a large, flattened bony structure on its snout and a smaller one above its eyes. These structures are called bosses. In each fossil site where Pachyrhinosaurus remains are found, there’s evidence', '[]', '/api/images/creatures/pachyrhinosaurus-canadensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('2cb36a8f8207ebf48d445', 'Panoplosaurus', 'Panoplosaurus mirus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 7.0, NULL, 'uncommon', 'Taxonomic details Taxonomy: Dinosauria, Ornithischia, Thyreophora, Ankylosauria, Nodosauridae Named by: Lambe (1919) Type species: mirus Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-height:100%;max-height:100%;object-fit:cover" sizes="100vw" srcSet="/discover/dino-directory/_next/image?u', '[]', '/api/images/creatures/panoplosaurus-mirus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('758870911b32cb4e85186', 'Pantydraco', 'Pantydraco caducus', 'Jurassic', 'Early Jurassic', 'Herbivorous', 3.0, NULL, 'common', 'Kingdom , Wales Knowledge about Pantydraco is based on a partial juvenile skeleton which was previously thought to be a Thecodontosaurus . Taxonomic details Taxonomy: Dinosauria, Saurischia Named by: Galton, Yates and Kermack 2007 (2003) Type species: caducus Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;ma', '[]', '/api/images/creatures/pantydraco-caducus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('367f8cb91af8b2e2fe3c6', 'Paralititan', 'Paralititan stromeri', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 28.0, NULL, 'rare', 'Paralititan has been found, but no skull, so reconstructions of the shape of the head are based on similar dinosaurs. The remains were found in a fossil mangrove swamp. Taxonomic details Taxonomy: Dinosauria, Saurischia, Sauropodomorpha, Sauropoda, Macronaria, Titanosauriformes, Titanosauria, Lithostrotia Named by: Smith, Lamanna, Lacovara, Dodson, Smith, Poole, Giegengack and Attia (2001) Type species: stromeri Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" sty', '[]', '/api/images/creatures/paralititan-stromeri.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('9f1da2a89c1bf3afafabb', 'Parasaurolophus', 'Parasaurolophus walkeri', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 9.0, 5000.0, 'epic', 'Parasaurolophus was a duck-billed dinosaur with a long, distinctive head crest. It lived in what is now North America during the Late Cretaceous Period. Over the years, experts have gone back and forth as to whether Parasaurolophus walked on two legs or four. We now think it did both. It probably spent most of its life walking on all fours, but it could raise itself onto its back legs. Fossilised skin impressions show that Parasaurolophus had scaly, pebbled skin. A dinosaur found in China called', '[]', '/api/images/creatures/parasaurolophus-walkeri.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('61356431a7a7e17fe826d', 'Parksosaurus', 'Parksosaurus warrenae', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 3.0, NULL, 'common', 'Taxonomic details Taxonomy: Dinosauria, Ornithischia, Ornithopoda, Euornithopoda Named by: Sternberg (1937) Type species: warrenae Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-height:100%;max-height:100%;object-fit:cover" sizes="100vw" srcSet="/discover/dino-directory/_next/image?url=htt', '[]', '/api/images/creatures/parksosaurus-warrenae.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('0cde94592ec4337258bfc', 'Patagosaurus', 'Patagosaurus fariasi', 'Jurassic', NULL, 'Herbivorous', 18.0, NULL, 'rare', 'Many Patagosaurus skeletons have been found. Taxonomic details Taxonomy: Dinosauria, Saurischia, Sauropodomorpha, Sauropoda, Eusauropoda, Cetiosauridae Named by: Bonaparte (1979) Type species: fariasi Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-height:100%;max-height:100%;object-fit:cov', '[]', '/api/images/creatures/patagosaurus-fariasi.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('e30e68c708857098cb921', 'Pelicanimimus', 'Pelicanimimus polyodon', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 2.5, NULL, 'common', 'Pelecanimimus had more than 200 very small, fine teeth in its mouth, which would have given it a bite that cut and ripped. The fossil that was first used to describe the species - which is known as a ''holotype'' - was well preserved. It showed scientists very clearly that this dinosaur had a throat pouch like those seen in today''s pelicans. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Ornithomimosauria Named by: Pérez-Moreno and colle', '[]', '/api/images/creatures/pelicanimimus-polyodon.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('312bf2823774aae24fe4f', 'Pelorosaurus', 'Pelorosaurus conybearei', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 25.0, NULL, 'rare', 'United Kingdom Taxonomic details Taxonomy: Dinosauria, Saurischia, Sauropodomorpha, Sauropoda, Macronaria, Titanosauriformes Named by: Mantell (1850) Type species: conybearei Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-height:100%;max-height:100%;object-fit:cover" sizes="100vw" srcSet="', '[]', '/api/images/creatures/pelorosaurus-conybearei.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('21ef47caf403ff01dd804', 'Pentaceratops', 'Pentaceratops sternbergi', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 6.8, NULL, 'uncommon', 'This dinosaur had a very large skull, almost 3m long. Taxonomic details Taxonomy: Dinosauria, Ornithischia, Ceratopsidae, Chasmosaurinae Named by: Osborn (1923) Type species: sternbergi Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-height:100%;max-height:100%;object-fit:cover" sizes="100v', '[]', '/api/images/creatures/pentaceratops-sternbergi.webp');
