INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('353f4a288008e596391da', 'Sinosauropteryx', 'Sinosauropteryx prima', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 1.1, NULL, 'common', 'Sinosauropteryx was a small, meat-eating dinosaur. It had a covering of primitive feathers, which were thin and hair-like. It was the first feathered dinosaur discovered that wasn''t directly related to birds. Another special thing about Sinosauropteryx is that scientists used it to work out a dinosaur''s colour pattern for the first time. Sinosauropteryx was a close relative of another small dinosaur, Compsognathus , which lived in Europe. When was Si', '[]', '/api/images/creatures/sinosauropteryx-prima.webp');
