INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('5da306ca1959a51f1c551', 'Stegosaurus', 'Stegosaurus armatus', 'Jurassic', 'Late Jurassic', 'Herbivorous', 9.0, NULL, 'legendary', 'Stegosaurus would have defended itself from predators like Allosaurus and Ceratosaurus with its powerful spiked tail. The bony plates along its back were embedded in the skin of the animal, not attached to its skeleton, which is why in most fossil finds the plates are separated from the body. When O C Marsh described the first fossil of a Stegosaurus , he concluded that the plates would have lain flat on its back. After finding a specimen that had been covered with mud, which had held the plates', '[]', '/api/images/creatures/stegosaurus-armatus.webp');
