INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('37d36853e52491b9bca5d', 'Talarurus', 'Talarurus plicatospineus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 6.0, NULL, 'uncommon', 'Talarurus is known from fairly complete skeletons. Taxonomic details Taxonomy: Dinosauria, Ornithischia, Thyreophora, Ankylosauria, Ankylosauridae Named by: Maleev (1952) Type species: plicatospineus Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-height:100%;max-height:100%;object-fit:cove', '[]', '/api/images/creatures/talarurus-plicatospineus.webp');
