INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('553b44e80e9a0168bbe7d', 'Therizinosaurus', 'Therizinosaurus cheloniformis', 'Cretaceous', 'Late Cretaceous', 'Unknown', 10.0, NULL, 'epic', 'Therizinosaurus was a large plant-eating dinosaur that walked on two legs. It had enormous claws on each of its three-fingered hands. These claws are thought to be the longest of any land animal ever. This dinosaur is only known from some arm, leg and rib bones. This means full body reconstructions are mostly guesswork based on closely related dinosaurs. What does Therizinosaurus mean? Therizinosaurus means ‘scythe lizard’. The dinosaur’s huge claws look like scythes – farming tools with long bl', '[]', '/api/images/creatures/therizinosaurus-cheloniformis.webp');
