INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('ae8819dce88a19e423056', 'Torvosaurus', 'Torvosaurus tanneri', 'Jurassic', 'Late Jurassic', 'Carnivorous', 10.0, NULL, 'uncommon', 'Portugal , USA Torvosaurus was one of the largest meat-eating dinosaurs of the Jurassic Period. It was closely related to Megalosaurus – the fir', '[]', '/api/images/creatures/torvosaurus-tanneri.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('948cb61dbae7e6b5bea3a', 'Triceratops', 'Triceratops horridus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 9.0, 10000.0, 'legendary', 'With its three horns, parrot-like beak and large frill that could reach nearly one metre across, the skull of Triceratops is one of the largest and most striking of any land animal. Triceratops might have used its horns to fend off attacks from Tyrannosaurus . A partial Triceratops fossil collected in 1997 has a horn that was bitten off, with bite marks that match Tyrannosaurus . The fossil shows that the horn healed after being bitten, indicating that at least some Triceratops survived these en', '[]', '/api/images/creatures/triceratops-horridus.webp');
