INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('06b921acce773fc9d5879', 'Tyrannosaurus', 'Tyrannosaurus rex', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 12.0, 7000.0, 'legendary', 'The ultimate carnivore Tyrannosaurus lives up to its reputation as one of the most fearsome animals of all time. Its powerful jaws had 60 teeth, each one up to 20cm (8 inches) long and its bite was around 3 times as powerful than that of a li', '[]', '/api/images/creatures/tyrannosaurus-rex.webp');
