INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('ed6cdbc5998367517db41', 'Unenlagia', 'Unenlagia comahuensis', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 2.4, NULL, 'common', 'Unenlagia is known from postcranial remains. The shoulder joint indicates a wide range of arm movements could be made. This may even have evolved from flying ancestors. Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Dromaeosauridae Named by: Novas and Puerta (1997) Type species: comahuensis <h2 class="text-step-4 font-headline font-semibold"', '[]', '/api/images/creatures/unenlagia-comahuensis.webp');
