INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('93dceb99ae11326c2b94f', 'Velociraptor', 'Velociraptor mongoliensis', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 1.8, 7.0, 'legendary', 'As portrayed in the Jurassic Park movies, Velociraptor was recreated at twice its actual size and closely modelled on Deinonychus . Though this was seen as unscientific at the time, soon after the first film was released, a dinosaur of the same type, Utahraptor , was discovered, even larger than', '[]', '/api/images/creatures/velociraptor-mongoliensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('6274acb6258fb0bfd42b3', 'Vulcanodon', 'Vulcanodon karibaensis', 'Jurassic', 'Early Jurassic', 'Herbivorous', 6.5, NULL, 'uncommon', '', '[]', '/api/images/creatures/vulcanodon-karibaensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('c73101232fd122d429890', 'Yandusaurus', 'Yandusaurus hongheensis', 'Jurassic', NULL, 'Herbivorous', 3.0, NULL, 'common', '', '[]', '/api/images/creatures/yandusaurus-hongheensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('e3f2a7d8f3fe7bae03f4b', 'Yangchuanosaurus', 'Yangchuanosaurus shangyouensis', 'Jurassic', 'Late Jurassic', 'Carnivorous', 10.0, NULL, 'uncommon', 'Taxonomic details Taxonomy: Dinosauria, Saurischia, Theropoda, Neotheropoda, Tetanurae, Avetheropoda, Carnosauria, Allosauroidea, Sinraptoridae Named by: Dong, Chang, Li and Zhou (1978) Type species: shangyouensis Discover more <a href="https://www.nhm.ac.uk/discover/how-dinosaurs-evolved-', '[]', '/api/images/creatures/yangchuanosaurus-shangyouensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('6bdda4a5b4f5f5f45f794', 'Yimenosaurus', 'Yimenosaurus youngi', 'Jurassic', 'Early Jurassic', 'Herbivorous', 9.0, NULL, 'uncommon', '', '[]', '/api/images/creatures/yimenosaurus-youngi.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('5e5da8147c1fcd0396cdd', 'Yingshanosaurus', 'Yingshanosaurus jichuanensis', 'Jurassic', 'Late Jurassic', 'Herbivorous', NULL, NULL, 'common', '', '[]', '/api/images/creatures/yingshanosaurus-jichuanensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('cf96688778fbbbe1c22c4', 'Yinlong', 'Yinlong downsi', 'Jurassic', NULL, 'Herbivorous', 1.2, NULL, 'common', 'The earliest known ceratopsian, showing features of ceratopsians, pachycephalosaurians and heterodontosaurids. Taxonomic details Taxonomy: Dinosauria, Ornithischia, Ceratopsia Named by: Xu, Forster, Clark and Mo (2006) Type species: downsi Discover more <img alt="" loading="lazy" decoding="async" data-nimg="responsive" style="position:absolute;top:0;left:0;bottom:0;right:0;box-sizing:border-box;padding:0;border:none;margin:auto;display:block;width:0;height:0;min-width:100%;max-width:100%;min-hei', '[]', '/api/images/creatures/yinlong-downsi.webp');
