INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('645a6daa83f75a524efb9', 'Zuniceratops', 'Zuniceratops christopheri', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', NULL, NULL, 'common', '', '[]', '/api/images/creatures/zuniceratops-christopheri.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('0e15d7874ccd5076e7d40', 'Pteranodon', 'Pteranodon longiceps', 'Cretaceous', 'Late Cretaceous', 'Unknown', 6.1, NULL, 'legendary', 'Pteranodon (; from Ancient Greek: πτερόν, romanized: pteron ''wing'' and ἀνόδων, anodon ''toothless'') is a genus of pterosaur that included some of the largest known flying reptiles, with P. longiceps having a wingspan of over 6 m (20 ft). They lived during the late Cretaceous geological period of North America in present-day Kansas, Nebraska, Wyoming, South Dakota and Alabama. More fossil specimens of Pteranodon have been found than any other pterosaur, with about 1,200 specimens known to science,', '[]', '/api/images/creatures/pteranodon-longiceps.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('6fca9014e8ce049aca94f', 'Quetzalcoatlus', 'Quetzalcoatlus northropi', 'Cretaceous', 'Late Cretaceous', 'Unknown', 25.9, NULL, 'legendary', 'Quetzalcoatlus () is a genus of azhdarchid pterosaur that lived during the Maastrichtian age of the Late Cretaceous in North America. The type specimen, recovered in 1971 from the Javelina Formation of Texas, United States, consists of several wing fragments and was described as Quetzalcoatlus northropi in 1975 by Douglas Lawson. The generic name refers to the Aztec serpent god of the sky, Quetzalcōātl, while the specific name honors Jack Northrop, designer of a tailless fixed-wing aircraft. The', '[]', '/api/images/creatures/quetzalcoatlus-northropi.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('30561de62981b69fb4471', 'Dimorphodon', 'Dimorphodon macronyx', 'Jurassic', 'Early Jurassic', 'Unknown', NULL, NULL, 'common', 'Dimorphodon ( dy-MOR-fə-don) is a genus of medium-sized pterosaur that lived in Europe during the early Jurassic Period (about 201-191 million years ago). It was named by paleontologist Richard Owen in 1859. Dimorphodon means "two-form tooth", derived from the Greek di- (δι-) meaning ''two'', morphḗ (μορφή) meaning ''shape'' and odṓn (ὀδών) meaning ''tooth'', referring to the fact that it had two distinct types of teeth in its jaws – which is comparatively rare among reptiles. The diet of Dimorphodon ', '[]', '/api/images/creatures/dimorphodon-macronyx.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('3c7ef7ccd0e0a2c48e5af', 'Rhamphorhynchus', 'Rhamphorhynchus muensteri', 'Jurassic', NULL, 'Unknown', NULL, NULL, 'common', 'Rhamphorhynchus (, from Ancient Greek rhamphos meaning "beak" and rhynchus meaning "snout") is a genus of long-tailed pterosaurs in the Jurassic period. Less specialized than contemporary, short-tailed pterodactyloid pterosaurs such as Pterodactylus, it had a long tail, stiffened with ligaments, which ended in a characteristic soft-tissue tail vane. The mouth of Rhamphorhynchus housed needle-like teeth, which were angled forward, with a curved, sharp, beak-like tip lacking teeth, indicating a di', '[]', '/api/images/creatures/rhamphorhynchus-muensteri.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('44ef73b0d8d32937bd772', 'Pterodactylus', 'Pterodactylus antiquus', 'Unknown', NULL, 'Unknown', NULL, NULL, 'common', 'Pterodactylus (from Ancient Greek: πτεροδάκτυλος, romanized: pterodáktylos ''winged finger'') is a genus of extinct pterosaurs. It is thought to contain only a single species, Pterodactylus antiquus, which was the first pterosaur to be named and identified as a flying reptile and one of the first prehistoric reptiles ever to be discovered.
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('9df22cd1641192ec61071', 'Tropeognathus', 'Tropeognathus mesembrinus', 'Cretaceous', 'Early Cretaceous', 'Unknown', 8.5, NULL, 'uncommon', 'Tropeognathus (meaning "keel jaw") is a genus of large pterosaurs from the late Early Cretaceous of South America. This genus is considered to be a member of the family Anhangueridae, but several studies have also recovered it within another family called Ornithocheiridae. Both of these families are diverse groups of pterosaurs known for their keel-tipped snouts and large size. With an estimated wingspan around 8.5 m (28 ft), Tropeognathus is regarded as the largest pterosaur found in the Southe', '[]', '/api/images/creatures/tropeognathus-mesembrinus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('e6798a5218dd154052af2', 'Tapejara', 'Tapejara wellnhoferi', 'Cretaceous', NULL, 'Unknown', 1.3, NULL, 'common', 'Tapejara (from a Tupi word meaning "the lord of the path") is a genus of Brazilian pterosaur from the Cretaceous Period (Santana Group, dating to about 127 to 112 million years ago). Tapejara crests consisted of a semicircular crest over the snout, and a bony prong which extended back behind the head. It was a small pterosaur, with a wingspan of approximately 1.23–1.3 metres (4.0–4.3 ft).', '[]', '/api/images/creatures/tapejara-wellnhoferi.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('c1b63ab663ed94f74a88b', 'Anhanguera', 'Anhanguera blittersdorffi', 'Cretaceous', 'Late Cretaceous', 'Unknown', NULL, NULL, 'common', 'Anhanguera (Portuguese: [ɐɲɐ̃ˈɡwɛɾɐ] ) is a genus of pterodactyloid pterosaur known from the Early Cretaceous (Albian age, 112 to 100 million years ago) Romualdo Formation of Brazil (precisely in Araripe Basin) and the Late Cretaceous (Cenomanian age, 98 to 93 million years ago) Kem Kem Group of Morocco. This pterosaur is closely related to Ornithocheirus, but belongs in the family Anhangueridae. The generic name comes from the Tupi words añanga, meaning "spirit protector of the animals" + wera ', '[]', '/api/images/creatures/anhanguera-blittersdorffi.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('c572e8eca28cb22ce13d4', 'Dsungaripterus', 'Dsungaripterus weii', 'Cretaceous', 'Early Cretaceous', 'Unknown', NULL, NULL, 'common', 'Dsungaripterus is a genus of dsungaripterid pterosaur which lived during the Early Cretaceous in what is now China and possibly South Korea. Its fossils come from the Wuerho Pterosaur Fauna group (WPF) of the Tugulu Group, comprising sections of the Lianmuqin and Shengjinkou Formations of the Junggar Basin. Both formations have been given various age estimates, with data suggesting at least some of the WPF date to the middle Valanginian, but the upper and lower bounds of these pterosaur bearing ', '[]', '/api/images/creatures/dsungaripterus-weii.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('d96282be99da9f1b92e1b', 'Nyctosaurus', 'Nyctosaurus gracilis', 'Cretaceous', 'Late Cretaceous', 'Unknown', NULL, NULL, 'common', 'Nyctosaurus (meaning "night lizard") is a genus of nyctosaurid pterosaur from the Late Cretaceous period of what is now the Niobrara Formation of the mid-western United States, which, during the time Nyctosaurus was alive, was covered in an extensive shallow sea. Some remains belonging to a possible Nyctosaurus species called "N." lamegoi have been found in Brazil, though it likely belongs to a different genus Simurghia. The genus Nyctosaurus has had numerous species referred to it, though how m', '[]', '/api/images/creatures/nyctosaurus-gracilis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('beb976161acead93ea06d', 'Plesiosaur', 'Plesiosaurus dolichodeirus', 'Jurassic', 'Early Jurassic', 'Unknown', 3.4, NULL, 'epic', 'Plesiosaurus (Greek: πλησίος (plesios), near to + σαῦρος (sauros), lizard) is a genus of extinct, large marine sauropterygian reptile that lived during the Early Jurassic. It is known by nearly complete skeletons from the Lias of England. Measuring around 3.5 m (11 ft) long, it is distinguishable by its small head, long and slender neck, broad turtle-like body, a short tail, and two pairs of large, elongated paddles. It lends its name to the order Plesiosauria, of which it is an early, but fairl', '[]', '/api/images/creatures/plesiosaurus-dolichodeirus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('8e06e085e774aa8e506ce', 'Mosasaurus', 'Mosasaurus hoffmannii', 'Cretaceous', 'Late Cretaceous', 'Unknown', 11.9, NULL, 'legendary', 'Mosasaurus (; "lizard of the Meuse River") is the type genus (defining example) of the Mosasauridae, an extinct group of aquatic squamate reptiles. It lived from about 82 to 66 million years ago during the Campanian and Maastrichtian stages of the Late Cretaceous. The genus was one of the first Mesozoic marine reptiles known to science—the first fossils of Mosasaurus were found as skulls in a chalk quarry near the Dutch city of Maastricht in the late 18th century, and were initially thought to b', '[]', '/api/images/creatures/mosasaurus-hoffmannii.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('8a38a0445fb72578e4397', 'Ichthyosaurus', 'Ichthyosaurus communis', 'Jurassic', 'Early Jurassic', 'Unknown', NULL, NULL, 'epic', 'Ichthyosaurus (derived from Greek ἰχθύς (ichthys) meaning ''fish'' and σαῦρος (sauros) meaning ''lizard'') is a genus of ichthyosaurs from the Early Jurassic (Hettangian - Pliensbachian) of Europe (Belgium, England, Germany and Portugal). Some specimens of the ichthyosaurid Protoichthyosaurus from England and Switzerland have been erroneously referred to this genus in the past. It is among the best known ichthyosaur genera, as it is the type genus of the order Ichthyosauria.', '[]', '/api/images/creatures/ichthyosaurus-communis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('20c8c6f8d9d68645b928e', 'Elasmosaurus', 'Elasmosaurus platyurus', 'Cretaceous', 'Late Cretaceous', 'Unknown', 10.4, NULL, 'epic', 'Elasmosaurus () is a genus of plesiosaur that lived in North America during the Campanian stage of the Late Cretaceous period, at about 80.6 to 77 million years ago. The first specimen was discovered in 1867 near Fort Wallace, Kansas, US, and was sent to the American paleontologist Edward Drinker Cope, who named it E. platyurus in 1868. The generic name means "thin-plate reptile", and the specific name means "flat-tailed". Cope originally reconstructed the skeleton of Elasmosaurus with the skull', '[]', '/api/images/creatures/elasmosaurus-platyurus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('a2fbf311fcf132b485355', 'Liopleurodon', 'Liopleurodon ferox', 'Jurassic', 'Late Jurassic', 'Carnivorous', 25.0, NULL, 'epic', 'Liopleurodon (; meaning ''smooth-sided teeth'') is an extinct genus of carnivorous pliosaurid plesiosaurs that lived from the Callovian stage of the Middle Jurassic to the  Kimmeridgian stage of the Late Jurassic period (approximately 166 to 155 million years ago). The type species is L. ferox, which is probably the only valid species. Some studies also include the second species L. pachydeirus, but this latter is considered as a probable junior synonym of L. ferox due to its lack of viable diagno', '[]', '/api/images/creatures/liopleurodon-ferox.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('b6576d7fe9ef666887970', 'Kronosaurus', 'Kronosaurus queenslandicus', 'Cretaceous', 'Early Cretaceous', 'Unknown', 13.1, NULL, 'uncommon', 'Kronosaurus ( KRON-oh-SOR-əs) is an extinct genus of large short-necked pliosaur that lived during the Aptian to Albian stages of the Early Cretaceous in what is now Australia. The first known specimen was received in 1899 and consists of a partially preserved mandibular symphysis, which was first thought to come from an ichthyosaur according to Charles De Vis. However, it was in 1924 that Albert Heber Longman formally described this specimen as the holotype of an imposing pliosaurid, to which h', '[]', '/api/images/creatures/kronosaurus-queenslandicus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('3639dfbb50dd61ccc3784', 'Nothosaurus', 'Nothosaurus mirabilis', 'Triassic', NULL, 'Unknown', NULL, NULL, 'common', 'Nothosaurus (''false lizard'', from the Ancient Greek νόθος, nothos, ''illegitimate'' and σαῦρος, sauros, ''lizard'') is an extinct genus of sauropterygian reptile from the Triassic period, approximately 245–228 million years ago, with fossils being distributed throughout the former Tethys Ocean, from North Africa and Europe to China. It is the best known member of the nothosaur order.', '[]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('d8f775ec4c8cd95c65a13', 'Tylosaurus', 'Tylosaurus proriger', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', NULL, NULL, 'common', 'Tylosaurus (; "knob lizard") is a genus of russellosaurine mosasaur (an extinct group of predatory marine lizards) that lived about 92 to 66 million years ago during the Turonian to Maastrichtian stages of the Late Cretaceous. Its fossils have been found primarily around North Atlantic Ocean including in North America, Europe, and Africa.', '[]', '/api/images/creatures/tylosaurus-proriger.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('002657e553f794dca683e', 'Thalassomedon', 'Thalassomedon haningtoni', 'Unknown', NULL, 'Unknown', NULL, NULL, 'common', 'Thalassomedon (from Greek, thalassa, "sea" and Greek, medon, "lord" or "ruler", meaning "sea lord") is a genus of plesiosaur, named by Welles in 1943.', '[]', '/api/images/creatures/thalassomedon-haningtoni.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('69b0db2b27de8a6d6cf5f', 'Shonisaurus', 'Shonisaurus popularis', 'Triassic', 'Late Triassic', 'Unknown', NULL, NULL, 'common', 'Shonisaurus is a genus of very large ichthyosaurs. At least 37 incomplete fossil specimens of the type species, Shonisaurus popularis, have been found in the Luning Formation of Nevada, USA. This formation dates to the late Carnian-early Norian age of the Late Triassic, around 227 million years ago. Other possible species of Shonisaurus have been discovered from the middle Norian deposits of Canada and Alaska.', '[]', '/api/images/creatures/shonisaurus-popularis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f6bbef1b5233c9c472015', 'Ophthalmosaurus', 'Ophthalmosaurus icenicus', 'Cretaceous', NULL, 'Unknown', 4.0, 940, 'common', 'Ophthalmosaurus (Greek ὀφθάλμος ophthalmos ''eye'' and σαῦρος sauros ''lizard'') is a genus of ichthyosaur known from the Middle-Late Jurassic. Possible remains from the earliest Cretaceous (Berriasian stage) are also known. It was a relatively medium-sized ichthyosaur, measuring 4 m (13 ft) long and weighing 940 kg (2,070 lb). Named for its extremely large eyes, it had a jaw containing many small but robust teeth. Major fossil finds of this genus have been recorded in Europe with a second species p', '[]', '/api/images/creatures/ophthalmosaurus-icenicus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('637452ad2f84747e04a67', 'Temnodontosaurus', 'Temnodontosaurus platyodon', 'Jurassic', NULL, 'Unknown', 9.1, NULL, 'uncommon', 'Temnodontosaurus (meaning "cutting-tooth lizard") is an extinct genus of large ichthyosaurs that lived during the Lower Jurassic in what is now Europe and possibly Chile. The first known fossil is a specimen consisting of a complete skull and partial skeleton discovered on a cliff by Joseph and Mary Anning around the early 1810s in Dorset, England. The anatomy of this specimen was subsequently analyzed in a series of articles written by Sir Everard Home between 1814 and 1819, making it the very ', '[]', '/api/images/creatures/temnodontosaurus-platyodon.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('e9619a98955ac222e38d7', 'Tanystropheus', 'Tanystropheus longobardicus', 'Triassic', NULL, 'Unknown', 6.1, NULL, 'uncommon', 'Tanystropheus (Ancient Greek: τανυ~ ''long'' + στροφευς ''hinged'') is an extinct genus of archosauromorph reptile which lived during the Triassic Period in Europe, Asia, and North America. It is recognisable by its extremely elongated neck, longer than the torso and tail combined. The neck was composed of 13 vertebrae strengthened by extensive cervical ribs. Tanystropheus is one of the most well-described non-archosauriform archosauromorphs, known from numerous fossils, including nearly complete sk', '[]', '/api/images/creatures/tanystropheus-longobardicus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('8d91db4c0a2f2add638b2', 'Smilodon', 'Smilodon fatalis', 'Quaternary', 'Pleistocene', 'Unknown', NULL, 78, 'legendary', 'Smilodon is a genus of extinct felids. It is one of the best-known saber-toothed predators and prehistoric mammals. Although commonly known as the saber-toothed tiger, it was not closely related to the tiger or other modern cats, belonging to the extinct subfamily Machairodontinae, with an estimated date of divergence from the ancestor of living cats around 20 million years ago. Smilodon was one of the last surviving machairodonts alongside Homotherium. Smilodon lived in the Americas during the ', '[]', '/api/images/creatures/smilodon-fatalis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('a7a243b0d225c69d82e21', 'Woolly Mammoth', 'Mammuthus primigenius', 'Quaternary', 'Pleistocene', 'Unknown', 2.4, 90, 'legendary', 'The woolly mammoth (Mammuthus primigenius) is an extinct species of mammoth that lived from the Middle Pleistocene until its extinction in the Holocene epoch. It was one of the last in a line of mammoth species, beginning with the African Mammuthus subplanifrons in the early Pliocene.  The woolly mammoth began to diverge from the steppe mammoth about 800,000 years ago in Siberia. Its closest extant relative is the Asian elephant. The Columbian mammoth (Mammuthus columbi) lived alongside the wool', '[]', '/api/images/creatures/mammuthus-primigenius.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('436be1eef56d05ac3eda9', 'Woolly Rhinoceros', 'Coelodonta antiquitatis', 'Quaternary', 'Pleistocene', 'Unknown', NULL, NULL, 'common', 'The woolly rhinoceros (Coelodonta antiquitatis) is an extinct species of rhinoceros that inhabited northern Eurasia during the Pleistocene epoch. The woolly rhinoceros was large, comparable in size to the largest living rhinoceros species, the white rhinoceros (Ceratotherium simum), and covered with long, thick hair that allowed it to survive in the extremely cold, harsh mammoth steppe. It had a massive hump reaching from its shoulder and fed mainly by grazing on herbaceous plants that grew in t', '[]', '/api/images/creatures/coelodonta-antiquitatis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('255eda55daf6cc9ec52c7', 'Megatherium', 'Megatherium americanum', 'Neogene', 'Pliocene', 'Unknown', NULL, NULL, 'epic', 'Megatherium ( meg-ə-THEER-ee-əm; from Greek méga (μέγα) ''great'' + theríon (θηρίον) ''beast'') is an extinct genus of ground sloths endemic to South America that lived from the Early Pliocene through the end of the Late Pleistocene. It is best known for the elephant-sized type species Megatherium americanum, commonly called the giant ground sloth or (less commonly) the megathere. It was primarily known from the Pampas, but ranged southwards to northernmost Patagonia and northwards to southern Boliv', '[]', '/api/images/creatures/megatherium-americanum.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('fb877ca85386b4716ee41', 'Glyptodon', 'Glyptodon clavipes', 'Neogene', 'Pliocene', 'Herbivorous', 2.0, 400, 'rare', 'Glyptodon (lit. ''grooved or carved tooth''; from Ancient Greek  γλυπτός (gluptós) ''sculptured'' and  ὀδοντ-, ὀδούς (odont-, odoús) ''tooth'') is a genus of glyptodont, an extinct group of large, herbivorous armadillos that lived from the Pliocene, around 3.2 million years ago, to the early Holocene, around 11,000 years ago, in South America. It is one of, if not the, best known genus of glyptodont. Glyptodon has a long and storied past, being the first named extinct cingulate and the type genus of t', '[]', '/api/images/creatures/glyptodon-clavipes.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('4f17c08268e7f9c578af6', 'Andrewsarchus', 'Andrewsarchus mongoliensis', 'Paleogene', 'Eocene', 'Unknown', NULL, NULL, 'common', 'Andrewsarchus (), meaning "Andrews'' ruler", is an extinct genus of artiodactyl that lived during the Middle Eocene in what is now China. The genus was first described by Henry Fairfield Osborn in 1924 with the type species A. mongoliensis based on a largely complete cranium. A second species, A. crassum, was described in 1977 based on teeth. A mandible, formerly described as Paratriisodon, does probably belong to Andrewsarchus as well. The genus has been historically placed in the families Meson', '[]', '/api/images/creatures/andrewsarchus-mongoliensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('0a219acbffbcfdcfa0768', 'Paraceratherium', 'Paraceratherium transouralicum', 'Paleogene', 'Oligocene', 'Unknown', 4.8, 17500, 'epic', 'Paraceratherium is an extinct genus of hornless rhinocerotoids belonging to the family Paraceratheriidae. It is one of the largest terrestrial mammals that has ever existed and lived from the Early to Late Oligocene epoch (34–23 million years ago). The first fossils were discovered in what is now Pakistan, and remains have been found across Eurasia between China and the Balkans. Paraceratherium means "near the hornless beast", in reference to Aceratherium, the genus in which the type species P. ', '[]', '/api/images/creatures/paraceratherium-transouralicum.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('6df23c7e0c56737ab70bb', 'Basilosaurus', 'Basilosaurus cetoides', 'Paleogene', 'Eocene', 'Carnivorous', 20.1, 15000, 'epic', 'Basilosaurus (meaning "king lizard") is a genus of large, predatory, prehistoric archaeocete whale from the late Eocene, approximately 41.3 to 33.9 million years ago (mya). First described in 1834, it was the first archaeocete and prehistoric whale known to science. Fossils attributed to the type species B. cetoides were discovered in the southeastern United States. The generic name, meaning "king lizard", was given due to the initial misconception about the fossil material as that of a giant re', '[]', '/api/images/creatures/basilosaurus-cetoides.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('9f0de63532b00cf3afe4b', 'Ambulocetus', 'Ambulocetus natans', 'Paleogene', 'Eocene', 'Unknown', NULL, NULL, 'common', 'Ambulocetus (from Latin ambulō, meaning "to walk", and cetus, meaning "whale", and thus, "walking whale") is a genus of early semiaquatic cetacean from the Kuldana Formation in Pakistan, roughly 48 or 47 million years ago during the Early Eocene (Lutetian). It contains one species, Ambulocetus natans (Latin natans "swimming"), known solely from one near-complete skeleton. Ambulocetus is among the best-studied of Eocene cetaceans, and serves as an instrumental find in the study of cetacean evolut', '[]', '/api/images/creatures/ambulocetus-natans.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f6acaebcc3fbcd84980aa', 'Pakicetus', 'Pakicetus inachus', 'Unknown', NULL, 'Unknown', 0.9, NULL, 'common', 'Pakicetus (meaning ''whale from Pakistan'') is an extinct genus of amphibious cetacean of the family Pakicetidae, which was endemic to South Asia during the Ypresian (early Eocene) period, about 50 million years ago. It was a wolf-like mammal, about 1–2 m (3 ft 3 in – 6 ft 7 in) long, and lived in and around water where it ate fish and other animals. The name Pakicetus comes from the fact that the first fossils of this extinct amphibious whale were discovered in Pakistan. The vast majority of pale', '[]', '/api/images/creatures/pakicetus-inachus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('e3387b189eade07f8393b', 'Deinotherium', 'Deinotherium giganteum', 'Neogene', 'Miocene', 'Unknown', 4.0, 12000, 'common', 'Deinotherium is an extinct genus of large, elephant-like proboscideans that lived from the Middle Miocene until the end of the Early Pleistocene. Although its appearance is reminiscent of modern elephants, Deinotherium differered considerably from modern elephants in several anatomical details: it possessed a notably more flexible neck, proportionally more slender limbs, tapir-like teeth, as well as tusks which grew down and curved back from the lower jaw (mandible), and lacked tusks growing fro', '[]', '/api/images/creatures/deinotherium-giganteum.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('96d3d4b393478c0e28380', 'Sivatherium', 'Sivatherium giganteum', 'Unknown', NULL, 'Unknown', NULL, NULL, 'common', 'Sivatherium ("Shiva''s beast", from Shiva and therium, Latinized form of Ancient Greek θηρίον - thēríon) is an extinct genus of giraffid that ranged throughout Africa and Eurasia. The species Sivatherium giganteum is, by weight, one of the largest giraffids known, and also one of the largest ruminants of all time. Sivatherium originated during the Late Miocene (around 7 million years ago) in Africa and survived through to the late Early Pleistocene (Calabrian) until around 1 million years ago.', '[]', '/api/images/creatures/sivatherium-giganteum.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('53017909764d7770114ba', 'Elasmotherium', 'Elasmotherium sibiricum', 'Unknown', NULL, 'Unknown', 4.6, 5000, 'common', 'Elasmotherium (from Ancient Greek ἔλασμα (élasma), meaning "metal plate" with the intended meaning "lamina" in reference to the tooth enamel, and θηρίον (theríon), meaning "beast") is an extinct genus of very large rhinoceros that lived in Eastern Europe, Central Asia and East Asia from the late Miocene through to the Late Pleistocene, until at least 39,000 years ago. It was the last surviving member of the subfamily Elasmotheriinae, a formerly diverse group of rhinoceroses separate from the sub', '[]', '/api/images/creatures/elasmotherium-sibiricum.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('9d4d48ee5520774af3515', 'Megalodon', 'Otodus megalodon', 'Neogene', 'Miocene', 'Unknown', 24.4, NULL, 'legendary', 'Otodus megalodon ( MEG-əl-ə-don; meaning "big tooth"), commonly known as megalodon, is an extinct species of giant mackerel shark that lived approximately 23 to 3.6 million years ago (Mya), from the Early Miocene to the Early Pliocene epochs. This prehistoric fish was once thought to be a member of the family Lamnidae and a close relative of the great white shark (Carcharodon carcharias), but has been reclassified into the extinct family Otodontidae, which diverged from the great white shark dur', '[]', '/api/images/creatures/otodus-megalodon.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f2d60f0bbadb61778ec14', 'Thylacosmilus', 'Thylacosmilus atrox', 'Neogene', 'Miocene', 'Unknown', NULL, 150, 'common', 'Thylacosmilus is an extinct genus of saber-toothed metatherian mammals that inhabited South America from the Late Miocene to Pliocene epochs. Though Thylacosmilus looks similar to the "saber-toothed cats", it was not a felid, like the well-known American Smilodon, but a sparassodont, a group closely related to marsupials, and only superficially resembled other saber-toothed mammals due to convergent evolution, with the aforementioned Thylacosmilus being one of the last known sparassodonts. A 200', '[]', '/api/images/creatures/thylacosmilus-atrox.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('ff53621a5084d98725dd3', 'Thylacoleo', 'Thylacoleo carnifex', 'Neogene', 'Pliocene', 'Carnivorous', NULL, 116, 'common', 'Thylacoleo ("pouch lion") is an extinct genus of carnivorous marsupials that lived in Australia from the late Pliocene to the Late Pleistocene (until around 40,000 years ago), often known as marsupial lions. They were the largest and last members of the family Thylacoleonidae, occupying the position of apex predator within Australian ecosystems. The largest and last species, Thylacoleo carnifex,  had an estimated average weight of 101 to 130 kg (223 to 287 lb), approaching the weight of a modern', '[]', '/api/images/creatures/thylacoleo-carnifex.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('6a5d61a205e6ddbde7221', 'Diprotodon', 'Diprotodon optatum', 'Quaternary', 'Pleistocene', 'Unknown', 1.5, 3500, 'common', 'Diprotodon, from Ancient Greek δί- (dí-), meaning "two", πρῶτος (prôtos), meaning "first", and ὀδούς (odoús), meaning "tooth", is an extinct genus of diprotodontid marsupial from the Pleistocene of Australia containing one species, D. optatum. The earliest finds date to 1.77 million to 780,000 years ago, but most specimens are dated to after 110,000 years ago. Its remains were first unearthed in 1830, in Wellington Caves, New South Wales, and contemporary paleontologists guessed they belonged to', '[]', '/api/images/creatures/diprotodon-optatum.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f05e044c4517283039aa3', 'Procoptodon', 'Procoptodon goliah', 'Quaternary', 'Pleistocene', 'Unknown', 2.0, 240, 'common', 'Procoptodon is an extinct genus of giant short-faced (sthenurine) kangaroos that lived in Australia during the Pleistocene Epoch. P. goliah, the largest known kangaroo species that ever existed, stood at about 2 m (6.6 ft). They weighed about 200–240 kg (440–530 lb). Other members of the genus were smaller, however; Procoptodon gilli was the smallest of all of the sthenurine kangaroos, standing approximately 1 m (3 ft 3 in) tall.
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('cd40926c17c4002acda1a', 'Megalania', 'Varanus priscus', 'Quaternary', 'Pleistocene', 'Unknown', 2.4, NULL, 'rare', 'Megalania  (Varanus priscus) is an extinct species of giant monitor lizard, part of the megafaunal assemblage that inhabited Australia during the Pleistocene. It is the largest terrestrial lizard known to have existed, but the fragmentary nature of known remains make estimates highly uncertain. Studies suggest that most known specimens would have reached around 2–2.4 m (6.6–7.9 ft) in body length excluding the tail, while some individuals would have been significantly larger, reaching sizes arou', '[]', '/api/images/creatures/varanus-priscus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('9c1e69bccc04b0d4a59a7', 'Arctodus', 'Arctodus simus', 'Quaternary', 'Pleistocene', 'Unknown', 1.5, 950, 'common', 'Arctodus is an extinct genus of short-faced bears that inhabited North America during the Pleistocene (about 2.6 Mya until 12,800 years ago). The two recognized species are the lesser short-faced bear (Arctodus pristinus) and the giant short-faced bear (Arctodus simus). Of these species, A. simus was larger, is known from more complete remains, and is considered one of the best-known members of North America''s extinct Ice Age megafauna. A. pristinus was largely restricted to the Early Pleistocen', '[]', '/api/images/creatures/arctodus-simus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('303b840e7b77d2b6fb1c6', 'Doedicurus', 'Doedicurus clavicaudatus', 'Unknown', NULL, 'Unknown', NULL, 1400, 'common', 'Doedicurus, from Ancient Greek δοῖδυξ (doîdux), meaning "pestle" and oυρά (ourá), meaning "tail", is an extinct genus of glyptodont from South America containing one species, D. clavicaudatus. Glyptodonts are a member of the family Chlamyphoridae, which also includes some modern armadillo species, and they are classified in the superorder Xenarthra alongside sloths and anteaters. Being a glyptodont, it was a rotund animal with heavy armor and a carapace. Averaging at an approximate 1,400 kg (3,1', '[]', '/api/images/creatures/doedicurus-clavicaudatus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('07c7d34cfc8f5e02321c8', 'Josephoartigasia', 'Josephoartigasia monesi', 'Neogene', 'Pliocene', 'Unknown', 0.3, 500, 'common', 'Josephoartigasia is an extinct genus of enormous dinomyid rodent from the Early Pliocene to Early Pleistocene of Uruguay. Its closest living relative is the pacarana. Josephoartigasia is named after Uruguayan national hero José Artigas. It contains two species: J. magna, described in 1966 based on a left mandible, and J. monesi, described in 2008 based on a nearly complete skull. Both are reported from the San José Member of the Raigón Formation by the Barrancas de San Gregorio along Kiyú beach.', '[]', '/api/images/creatures/josephoartigasia-monesi.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('7953e9585b3fe373132e0', 'Terror Bird', 'Phorusrhacos longissimus', 'Unknown', NULL, 'Unknown', NULL, NULL, 'epic', 'Phorusrhacos ( FOR-əs-RAH-koss) is an extinct genus of giant flightless terror birds that inhabited South America during the Miocene epoch. Phorusrhacos was one of the dominant land predators in South America at the time it existed. It is thought to have lived in woodlands and grasslands.', '[]', '/api/images/creatures/phorusrhacos-longissimus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('d9d0d1ee8e40679c457e2', 'Gastornis', 'Gastornis gigantea', 'Paleogene', 'Eocene', 'Unknown', NULL, NULL, 'common', 'Gastornis is an extinct genus of large, flightless birds that lived during the mid-Paleocene to mid-Eocene epochs of the Paleogene period. Most fossils have been found in Europe, and some species typically referred to the genus are known from North America and Asia. Several genera, including the well-studied genus Diatryma, have historically been considered junior synonyms of Gastornis. However, this interpretation has been challenged recently, and some researchers currently consider Diatryma to', '[]', '/api/images/creatures/gastornis-gigantea.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('4ce99f43df3c6b75815be', 'Titanoboa', 'Titanoboa cerrejonensis', 'Paleogene', 'Eocene', 'Unknown', 12.8, 932, 'legendary', 'Titanoboa (; lit. ''titanic boa'') is a genus of extinct giant boid snake (being the biological family of all boas and anacondas) that lived during the middle and late Paleocene epoch. Titanoboa was first discovered in the early 2000s by members of the Smithsonian Tropical Research Institute, which–along with students from the University of Florida–recovered 186 fossils of Titanoboa from the Cerrejón coal mines in the La Guajira department of northeastern Colombia. It was named and described in 20', '[]', '/api/images/creatures/titanoboa-cerrejonensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('39eae41eb01380c18a80d', 'Sarcosuchus', 'Sarcosuchus imperator', 'Cretaceous', 'Early Cretaceous', 'Unknown', 9.5, 4300, 'epic', 'Sarcosuchus (), from Ancient Greek σάρξ (sárx), meaning "flesh", and Σοῦχος (Soûkhos), meaning "Sobek", is an extinct genus of crocodyliform that lived during the Early Cretaceous, from the late Hauterivian to the early Albian stages, 130 to 112 million years ago of what is now Africa and South America. It was one of the largest pseudosuchians, with the largest specimen of S. imperator reaching approximately 9–9.5 metres (29.5–31.2 ft) long and weighing up to 3.45–4.3 metric tons (3.80–4.74 shor', '[]', '/api/images/creatures/sarcosuchus-imperator.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('e6497d5606bbd2ee9d8ec', 'Deinosuchus', 'Deinosuchus hatcheri', 'Cretaceous', 'Late Cretaceous', 'Unknown', 10.7, NULL, 'uncommon', 'Deinosuchus is an extinct genus of eusuchian, either an alligatoroid crocodilian or a stem-group crocodilian, which lived during the Late Cretaceous around 82 to 73 million years ago. The first remains were discovered in North Carolina (United States) in the 1850s, and the genus was first described in 1909. Additional fragments were discovered in the 1940s and were later incorporated into an influential, though inaccurate, skull reconstruction at the American Museum of Natural History. Knowledge', '[]', '/api/images/creatures/deinosuchus-hatcheri.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('d8efff19fee494e3f4bc6', 'Kaprosuchus', 'Kaprosuchus saharicus', 'Cretaceous', NULL, 'Unknown', NULL, NULL, 'common', 'Kaprosuchus is an extinct genus of mahajangasuchid crocodyliform. It is known from a single nearly complete skull collected from the Upper Cretaceous Echkar Formation of Niger. The name means "boar crocodile" from the Greek κάπρος, kapros ("boar") and σοῦχος, soukhos ("crocodile") in reference to its unusually large caniniform teeth which resemble those of a boar. It has been nicknamed "BoarCroc" by Paul Sereno and Hans Larsson, who first described the genus in a monograph published in ZooKeys i', '[]', '/api/images/creatures/kaprosuchus-saharicus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('0ce7dfa0f699faf39a445', 'Quinkana', 'Quinkana fortirostrum', 'Unknown', NULL, 'Unknown', 3.0, 200, 'common', 'Quinkana is an extinct genus of mekosuchine crocodylians that lived in Australia from about 25 million to about 10,000 years ago, with the majority of fossils having been found in Queensland. Four species are currently recognized, all of which have been named between 1981 and 1997. The two best understood species are Q. fortirostrum, the type species, and Q. timara, a more gracile form from the Miocene. The other two species, Q. babarra and Q. meboldi, from the Pliocene and Oligocene respectivel', '[]', '/api/images/creatures/quinkana-fortirostrum.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('72142fce5b2456d184b60', 'Dimetrodon', 'Dimetrodon grandis', 'Permian', 'Early Permian', 'Unknown', 4.6, 250, 'epic', 'Dimetrodon ( or  ; lit. ''two measures of teeth'') is an extinct genus of sphenacodontid synapsid that lived during the Cisuralian (Early Permian) epoch of the Permian period, around 295–272 million years ago. With most species measuring 1.7–4.6 m (5.6–15.1 ft) long and weighing 28–250 kg (62–551 lb), the most prominent feature of Dimetrodon is the large neural spine sail on its back formed by elongated spines extending from the vertebrae. It was an obligate quadruped (it could walk only on four l', '[]', '/api/images/creatures/dimetrodon-grandis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('732348007567590971011', 'Edaphosaurus', 'Edaphosaurus pogonias', 'Unknown', NULL, 'Unknown', NULL, NULL, 'common', 'Edaphosaurus (, meaning "pavement lizard" for dense clusters of its teeth) is a genus of extinct edaphosaurid synapsids that lived in what is now North America and Europe around 303.4 to 272.5 million years ago, during the Late Carboniferous to Early Permian.  The American paleontologist Edward Drinker Cope first described Edaphosaurus in 1882, naming it for the "dental pavement" on both the upper and lower jaws, from the Greek edaphos έδαφος ("ground"; also "pavement") and σαῦρος (sauros) ("liz', '[]', '/api/images/creatures/edaphosaurus-pogonias.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('4b1b23cfa5bb158bb2c4b', 'Gorgonops', 'Gorgonops torvus', 'Permian', 'Late Permian', 'Unknown', NULL, NULL, 'rare', 'Gorgonops (from Greek: Γοργών ''Gorgon'' and ὤψ ''eye, face'', literally ''Gorgon eye'' or ''Gorgon face'') is an extinct genus of gorgonopsian therapsid, of which it is the type genus. Gorgonops lived during the Late Permian (Wuchiapingian), about 260–254 million years ago in what is now South Africa.', '[]', '/api/images/creatures/gorgonops-torvus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('7ae1799df4464720df41e', 'Inostrancevia', 'Inostrancevia alexandri', 'Permian', 'Late Permian', 'Carnivorous', 3.2, NULL, 'common', 'Inostrancevia is an extinct genus of large carnivorous therapsids which lived during the Late Permian in what is now European Russia and Southern Africa. The first-known fossils of this gorgonopsian were discovered in the context of a long series of excavations carried out from 1899 to 1914 in the Northern Dvina, Russia. Among these are two near-complete skeletons embodying the first described specimens of this genus, being also the first gorgonopsian identified in Russia. Several other fossil m', '[]', '/api/images/creatures/inostrancevia-alexandri.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('fd0df697f5670a99b6b02', 'Scutosaurus', 'Scutosaurus karpinskii', 'Unknown', NULL, 'Unknown', NULL, NULL, 'common', 'Scutosaurus ("shield lizard") is an extinct genus of pareiasaur parareptiles. Its genus name refers to large plates of armor scattered across its body. It was a large anapsid reptile that, unlike most reptiles, held its legs underneath its body to support its great weight. Fossils have been found in the Sokolki Assemblage Zone of the Malokinelskaya Formation in European Russia, close to the Ural Mountains, dating to the late Permian (Lopingian) between 259 and 252 million years ago.', '[]', '/api/images/creatures/scutosaurus-karpinskii.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('5917f2d60fc7252bec007', 'Moschops', 'Moschops capensis', 'Unknown', NULL, 'Unknown', NULL, NULL, 'common', 'Moschops (Greek for "calf face") is an extinct genus of therapsids that lived in the Guadalupian epoch, around 265–260 million years ago. They were heavily built plant eaters, and they may have lived partly in water, as hippopotamuses do. They had short, thick heads and might have competed by head-butting each other. Their elbow joints allowed them to walk with a more mammal-like gait rather than crawling. Their remains were found in the Karoo region of South Africa, belonging to the Tapinocepha', '[]', '/api/images/creatures/moschops-capensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('6149e77319d63f2ed4e08', 'Lystrosaurus', 'Lystrosaurus murrayi', 'Unknown', NULL, 'Herbivorous', 2.4, NULL, 'common', 'Lystrosaurus (; ''shovel lizard''; proper Ancient Greek is λίστρον lístron ''tool for leveling or smoothing, shovel, spade, hoe'') is an extinct genus of herbivorous dicynodont therapsids from the late Permian and Early Triassic epochs (around 248 million years ago). It lived in what is now Antarctica, India, China, Mongolia, European Russia and South Africa. Four to six species are currently recognized, although from the 1930s to 1970s the number of species was thought to be much higher. They range', '[]', '/api/images/creatures/lystrosaurus-murrayi.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('666beaab57e56943e2917', 'Diictodon', 'Diictodon feliceps', 'Permian', 'Late Permian', 'Unknown', NULL, NULL, 'common', 'Diictodon (meaning "two weasel teeth") is an extinct genus of pylaecephalid dicynodont that lived during the Late Permian period, approximately 255 million years ago. Fossils have been found in the Cistecephalus Assemblage Zone of the Madumabisa Mudstone of the Luangwa Basin in Zambia and the Tropidostoma Assemblage Zone of the Teekloof Formation, Tapinocephalus Assemblage Zone of the Abrahamskraal Formation, Dicynodon Assemblage Zone of the Balfour Formation, Cistecephalus Assemblage Zone of th', '[]', '/api/images/creatures/diictodon-feliceps.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f64b722101fc7b371eda5', 'Postosuchus', 'Postosuchus kirkpatricki', 'Triassic', 'Late Triassic', 'Unknown', 6.1, NULL, 'uncommon', 'Postosuchus, meaning "Crocodile from  Post", is an extinct genus of rauisuchid reptiles comprising two species, P. kirkpatricki and P. alisonae, that lived in what is now North America during the Late Triassic. Postosuchus is a member of the clade Pseudosuchia, the lineage of archosaurs that includes modern crocodilians (the other main group of archosaurs is Avemetatarsalia, the lineage that includes all archosaurs more closely related to birds than to crocodilians). Its name refers to Post Quar', '[]', '/api/images/creatures/postosuchus-kirkpatricki.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f033504f8e9239e47e26a', 'Desmatosuchus', 'Desmatosuchus spurensis', 'Unknown', NULL, 'Unknown', NULL, NULL, 'common', 'Desmatosuchus (, from Greek δεσμός desmos ''link'' + σοῦχος soûkhos ''crocodile'') is an extinct genus of archosaur belonging to the Order Aetosauria. It lived in North America and potentially India (cf. Desmatosuchus) during the Late Triassic.', '[]', '/api/images/creatures/desmatosuchus-spurensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('c51e42a8e78fb6a554ecd', 'Anomalocaris', 'Anomalocaris canadensis', 'Unknown', NULL, 'Unknown', NULL, NULL, 'legendary', 'Anomalocaris (from Ancient Greek ανώμαλος, meaning "unlike", and καρίς, meaning "shrimp", with the intended meaning "unlike other shrimp") is an extinct genus of radiodont, an order of early-diverging stem-group marine arthropods. It is best known from the type species A. canadensis, found in the Stephen Formation (particularly the Burgess Shale) of British Columbia, Canada. The other named species A. daleyae is known from the somewhat older Emu Bay Shale of Australia. Other unnamed Anomalocaris', '[]', '/api/images/creatures/anomalocaris-canadensis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('ef2ebf8b7d371083642a5', 'Hallucigenia', 'Hallucigenia sparsa', 'Cambrian', NULL, 'Unknown', NULL, NULL, 'rare', 'Hallucigenia is a genus of lobopodian known from Cambrian-aged fossils in Burgess Shale-type deposits in Canada (Burgess Shale) and China, and from isolated  spines around the world. The generic name reflects the type species'' unusual appearance and eccentric history of study; when it was erected as a genus, H. sparsa was reconstructed as an enigmatic animal upside down and back to front. Lobopodians are a grade of Paleozoic panarthropods from which the velvet worms, water bears, and arthropods ', '[]', '/api/images/creatures/hallucigenia-sparsa.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('67a94f428341aca1176c4', 'Opabinia', 'Opabinia regalis', 'Cambrian', NULL, 'Unknown', NULL, NULL, 'rare', 'Opabinia regalis is an extinct, stem group marine arthropod found in the Middle Cambrian Burgess Shale Lagerstätte (505 million years ago) of British Columbia. Opabinia was a soft-bodied animal, measuring up to 7 cm in body length, and had a segmented trunk with flaps along its sides and a fan-shaped tail. The head showed unusual features: five eyes, a mouth under the head and facing backwards, and a clawed proboscis that most likely passed food to its mouth. Opabinia lived on the seafloor, usin', '[]', '/api/images/creatures/opabinia-regalis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('d9875d74f19d0146ba240', 'Wiwaxia', 'Wiwaxia corrugata', 'Cambrian', NULL, 'Unknown', NULL, NULL, 'common', 'Wiwaxia is a genus of prehistoric soft-bodied animals that were covered in carbonaceous scales and spines that protected it from predators. Wiwaxia fossils—mainly isolated scales, but sometimes complete, articulated fossils—are known from early Cambrian and middle Cambrian fossil deposits across the globe. The living animal would have measured up to 5 centimetres (2 in) when fully grown, although a range of juvenile specimens are known, the smallest being 2 millimetres (0.08 in) long.
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('5c526097fcdc46eb4c220', 'Trilobite', 'Paradoxides davidis', 'Cambrian', NULL, 'Unknown', NULL, NULL, 'rare', 'Paradoxides is a genus of large to very large trilobite found throughout the world during the Middle Cambrian period. One record-breaking specimen of Paradoxides davidis, described by John William Salter in 1863, is 37 cm (15 in). The cephalon was semicircular with free cheeks ending in long, narrow, recurved spines. Eyes were crescent shaped providing an almost 360° view, but only in the horizontal plane. Its elongate thorax was composed of 19–21 segments and adorned with longish, recurved pleu', '[]', '/api/images/creatures/paradoxides-davidis.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('3be414611ffde1303b85b', 'Eurypterus', 'Eurypterus remipes', 'Silurian', NULL, 'Unknown', NULL, NULL, 'rare', 'Eurypterus ( yoo-RIP-tər-əs) is an extinct genus of eurypterid, a group of organisms commonly called "sea scorpions". The genus lived during the Silurian period, from around 432 to 418 million years ago. Eurypterus is by far the most well-studied and well-known eurypterid. Eurypterus fossil specimens probably represent more than 95% of all known eurypterid specimens.
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('44cab61385d17bb1dda1e', 'Cameroceras', 'Cameroceras trentonense', 'Ordovician', NULL, 'Unknown', 2.0, NULL, 'common', 'Cameroceras, from Ancient Greek καμάρα (kamára), meaning "chamber", and κέρας (kéras), meaning "horn", is an extinct genus of endocerid cephalopod which lived in equatorial oceans during the entire Ordovician period. Like other endocerids, it was an orthocone, meaning that its shell was fairly straight and pointed. It was particularly abundant and widespread in the Late Ordovician, inhabiting the shallow tropical seas in and around Laurentia, Baltica and Siberia (equivalent to modern North Ameri', '[]', '/api/images/creatures/cameroceras-trentonense.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('f16fae5af342a3e4dff6d', 'Dunkleosteus', 'Dunkleosteus terrelli', 'Devonian', 'Late Devonian', 'Unknown', 7.0, 4000, 'legendary', 'Dunkleosteus is an extinct genus of large arthrodire ("jointed-neck") fish that existed during the Late Devonian period, about 382–358 million years ago. It was a pelagic fish inhabiting open waters, and one of the first vertebrate apex predators of any ecosystem. Fossils of Dunkleosteus have been found in the United States, Canada, Poland, Belgium, and Morocco.
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('10c5d62d87fbb2fdf23f0', 'Tiktaalik', 'Tiktaalik roseae', 'Devonian', 'Late Devonian', 'Unknown', 2.7, NULL, 'rare', 'Tiktaalik (; Inuktitut: ᑎᒃᑖᓕᒃ [tiktaːlik]) is a monospecific genus of extinct sarcopterygian (lobe-finned fish) from the late Devonian Period, about 375 Mya (million years ago), having many features similar to those of tetrapods (four-legged animals). Tiktaalik is estimated to have had a total length of 1.25–2.75 metres (4.1–9.0 ft) on the basis of various specimens.
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('b37784633a551e4bfd308', 'Acanthostega', 'Acanthostega gunnari', 'Devonian', 'Late Devonian', 'Unknown', NULL, NULL, 'rare', 'Acanthostega, from Ancient Greek ἄκανθα (ákantha), meaning "spine", and στέγη (stégē), meaning "roof", is an extinct genus of stem-tetrapod, among the first vertebrate animals to have recognizable limbs. It appeared in the late Devonian period (Famennian age) about 365 million years ago, and was anatomically intermediate between lobe-finned fishes and those that were able to come onto land.', '[]', '/api/images/creatures/acanthostega-gunnari.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('30a93e6d964e970d6006e', 'Helicoprion', 'Helicoprion davisii', 'Permian', NULL, 'Unknown', 11.9, NULL, 'epic', 'Helicoprion is an extinct genus of large shark-like cartilaginous fish that lived from the Early to the Middle Permian, about 290-270 million years ago. Helicoprion is a member of the Eugeneodontiformes, an extinct order of cartilaginous fish within the clade Holocephali, a group today represented only by chimaeras. It is also the type genus of the Helicoprionidae, a family of eugeneodonts characterised by distinctive tooth structures called tooth whorls. Helicoprion was first named in 1899 by A', '[]', '/api/images/creatures/helicoprion-davisii.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('6a863f7ce88a395aa43e3', 'Cooksonia', 'Cooksonia pertoni', 'Devonian', NULL, 'Unknown', NULL, NULL, 'common', 'Cooksonia is an extinct group of primitive land plants, treated as a genus, although probably not monophyletic. The earliest Cooksonia date from the middle of the Silurian (the Wenlock epoch); the group continued to be an important component of the flora until the end of the Early Devonian, a total time span of 433 to 393 million years ago. While Cooksonia fossils are distributed globally, most type specimens come from Britain, where they were first discovered in 1937. Cooksonia includes the old', '[]', '/api/images/creatures/cooksonia-pertoni.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('9f9d5982ad3d16088c241', 'Aegirocassis', 'Aegirocassis benmoulai', 'Ordovician', NULL, 'Carnivorous', NULL, NULL, 'common', 'Aegirocassis (″Aegir''s helmet″) is an extinct genus of giant radiodont arthropod belonging to the family Hurdiidae that lived 480 million years ago during the early Ordovician in the Fezouata Formation of Morocco. It is known by a single species, Aegirocassis benmoulai. Van Roy initiated scientific study of the fossil, the earliest known of a "giant" filter-feeder discovered to date. Aegirocassis is considered to have evolved from early predatory radiodonts. This animal is characterized by its l', '[]', '/api/images/creatures/aegirocassis-benmoulai.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('b1dd5e246671097501d8c', 'Arthropleura', 'Arthropleura armata', 'Unknown', NULL, 'Unknown', 1.8, NULL, 'epic', 'Arthropleura, from Ancient Greek ἄρθρον (árthron), meaning "joint", and πλευρά (pleurá), meaning "rib", is an extinct genus of massive myriapod that lived in what is now Europe and North America around 344 to 292 million years ago, from the Viséan stage of the lower Carboniferous period to the Sakmarian stage of the lower Permian period. It was a millipede, and was capable of reaching at least 2 metres (6 ft 7 in) in length, possibly up to over 2.5 metres (8 ft 2 in), making it the largest known', '[]', '/api/images/creatures/arthropleura-armata.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('bdc33468cbbacc15f0a77', 'Meganeura', 'Meganeura monyi', 'Carboniferous', NULL, 'Carnivorous', 0.7, NULL, 'common', 'Meganeura (Ancient Greek: μέγα (large) + νευρόν (vein or nerve)) is a genus of extinct insects from the Late Carboniferous (approximately 300 million years ago). It is a member of the extinct order Meganisoptera, which are closely related to and resemble dragonflies and damselflies (with dragonflies, damselflies and meganisopterans being part of the broader group Odonatoptera). Like other odonatopterans, they were predatory, with their diet mainly consisting of other insects. 
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('3f2a2017e4abb67c59072', 'Dodo', 'Raphus cucullatus', 'Unknown', NULL, 'Unknown', 0.7, 18, 'rare', 'The dodo (Raphus cucullatus) is an extinct flightless bird that was endemic to Mauritius,  an island east of Madagascar in the Indian Ocean. The dodo''s closest relative was the also-extinct and flightless Rodrigues solitaire. The two formed the subtribe Raphina, a clade of extinct flightless birds that are a part of the group that includes pigeons and doves (the family Columbidae). The closest living relative of the dodo is the Nicobar pigeon. A white dodo was once thought to have existed on the', '[]', '/api/images/creatures/raphus-cucullatus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('6db5b0ed6a3f682d3c5ee', 'Moa', 'Dinornis robustus', 'Unknown', NULL, 'Unknown', NULL, NULL, 'rare', 'The South Island giant moa (Dinornis robustus) is an extinct species of moa in the genus Dinornis, known in Māori by the name moa nunui. It was one of the tallest-known bird species to walk the Earth, exceeded in weight only by the heavier but shorter extinct elephant bird of Madagascar.', '[]', '/api/images/creatures/dinornis-robustus.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('5ee386da7094c6c5e613a', 'Haast''s Eagle', 'Hieraaetus moorei', 'Unknown', NULL, 'Unknown', NULL, 18, 'common', 'Haast''s eagle (Hieraaetus moorei), sometimes known as Fuller''s eagle, is an extinct species of eagle that lived in the South Island of New Zealand, commonly accepted to be the pouākai of Māori mythology. It is the largest eagle known to have existed, with an estimated weight of 10–18 kilograms (22–40 pounds), compared to the next-largest and extant harpy eagle (Harpia harpyja), at up to 9 kg (20 lb). Its massive size is explained as an evolutionary response to the size of its prey—the flightless', '[]', '/api/images/creatures/hieraaetus-moorei.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('896cd33089a52403c1cb9', 'Elephant Bird', 'Aepyornis maximus', 'Unknown', NULL, 'Unknown', NULL, NULL, 'common', 'Aepyornis is an extinct genus of elephant bird formerly endemic to Madagascar. The genus had two species, the smaller A. hildebrandti and the larger A. maximus, which is possibly the largest bird ever to have lived. Its closest living relative is the New Zealand kiwi. They became extinct sometime around AD 1000, probably as a result of human activity.', '[]', NULL);
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('c5cd7263801dfae0608fd', 'Argentavis', 'Argentavis magnificens', 'Neogene', 'Miocene', 'Unknown', NULL, NULL, 'epic', 'Argentavis is an extinct genus of teratornithid known from three sites in the Epecuén and Andalhualá Formations in central and northwestern Argentina dating to the Late Miocene (Huayquerian). The type species, A. magnificens, is sometimes called the giant teratorn. Argentavis was among the largest flying birds to ever exist, holding the record for heaviest flying bird, although it was surpassed in wingspan after the 2014 description of Pelagornis sandersi, which is estimated to have possessed wi', '[]', '/api/images/creatures/argentavis-magnificens.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('a06b549c9518c063bf076', 'Pelagornis', 'Pelagornis sandersi', 'Paleogene', 'Oligocene', 'Unknown', NULL, NULL, 'common', 'Pelagornis is an extinct genus of prehistoric pseudotooth birds, a group of extinct seabirds. Species span from the Oligocene to the Early Pleistocene. Members of Pelagornis represent among the largest pseudotooth birds, with one species, P. sandersi, having the widest wingspan of any bird known.', '[]', '/api/images/creatures/pelagornis-sandersi.webp');
INSERT INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url) VALUES ('2f7702d3e73f5056a7631', 'Yutyrannus', 'Yutyrannus huali', 'Cretaceous', 'Early Cretaceous', 'Unknown', NULL, NULL, 'epic', 'Yutyrannus (meaning "feathered tyrant") is a genus of proceratosaurid tyrannosauroid dinosaur which contains a single known species, Yutyrannus huali. This species lived during the early Cretaceous period in what is now northeastern China. Three fossils of Yutyrannus huali — all found in the rock beds of Liaoning Province — are the largest-known dinosaur specimens that preserve direct evidence of feathers.', '[]', '/api/images/creatures/yutyrannus-huali.webp');
